import { useState, useEffect, useCallback, useRef } from 'react';
import { ComparisonSelector } from '@/components/comparison/comparison-selector';
import { ComparisonChartUPlot as ComparisonChart } from '@/components/comparison/comparison-chart-uplot';
import { AxisSelector, LegendToggle, ExperimentChip, ViscosityThresholdControl } from '@/components/comparison/comparison-controls';
import { Layers, Plus, Settings2, AlertCircle } from 'lucide-react';
import type { Experiment } from '@/types';
import { useComparisonStore } from '@/lib/store/comparison-store';
import { checkExperimentsExist } from '@/lib/experiments/client';
import { useShallow } from 'zustand/react/shallow';

const METRICS = [
    { value: 'viscosity_cp', label: 'Вязкость' },
    { value: 'temperature_c', label: 'Температура' },
    { value: 'bath_temperature_c', label: 'Темп. бани' },
    { value: 'speed_rpm', label: 'Скорость' },
    { value: 'shear_rate_s1', label: 'Скор. сдвига' },
    { value: 'shear_stress_pa', label: 'Напр. сдвига' },
    { value: 'pressure_bar', label: 'Давление' },
];

export default function ComparisonPage() {
    // Fine-grained selectors: each subscription only re-renders when its own
    // slice changes, preventing displaySettings changes from re-rendering the
    // chart and vice-versa.
    const experiments = useComparisonStore(s => s.experiments);
    const displaySettings = useComparisonStore(useShallow(s => s.displaySettings));
    const addExperiment = useComparisonStore(s => s.addExperiment);
    const removeExperiment = useComparisonStore(s => s.removeExperiment);
    const updateDisplaySettings = useComparisonStore(s => s.updateDisplaySettings);
    const getMaxExperiments = useComparisonStore(s => s.getMaxExperiments);
    const isInComparison = useComparisonStore(s => s.isInComparison);
    const rehydrateIfNeeded = useComparisonStore(s => s.rehydrateIfNeeded);
    const _hasHydrated = useComparisonStore(s => s._hasHydrated);
    const maxExperiments = getMaxExperiments();

    // Re-hydrate stale experiments only after zustand/persist has finished loading
    // from localStorage. Without this guard, rehydrateIfNeeded() sees experiments=[]
    // (the initial store state) and returns early — leaving the page blank when the
    // user navigates away and back before the async hydration completes.
    useEffect(() => {
        if (!_hasHydrated) return;
        rehydrateIfNeeded();
    // eslint-disable-next-line react-hooks/exhaustive-deps -- run once after hydration
    }, [_hasHydrated]);

    // Deferred existence check: 2 s after mount, verify that DB-backed experiments
    // still exist.  If the user deleted an experiment from the library while it was
    // cached in comparison (with columnarData retained), this removes the stale entry.
    // Uses a lightweight SELECT id … WHERE id IN (…) — no heavy data loading.
    useEffect(() => {
        if (!_hasHydrated) return;
        const timer = setTimeout(async () => {
            const state = useComparisonStore.getState();
            const dbIds = state.experiments
                .filter(e => !e.id.startsWith('file-'))
                .map(e => e.id);
            if (dbIds.length === 0) return;
            try {
                const res = await checkExperimentsExist(dbIds);
                const existing = new Set(res.existingIds);
                const before = useComparisonStore.getState().experiments;
                const after = before.filter(
                    e => e.id.startsWith('file-') || existing.has(e.id),
                );
                if (after.length < before.length) {
                    useComparisonStore.setState({ experiments: after });
                }
            } catch {
                // Non-critical — existence check is best-effort
            }
        }, 2_000);
        return () => clearTimeout(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps -- run once after hydration
    }, [_hasHydrated]);

    // NOTE: releaseHeavyData() on unmount was REMOVED.  Keeping columnarData
    // TypedArrays in-memory (~120 KB × 6 experiments = 720 KB) is negligible
    // compared to the IPC cost of re-fetching N experiments from SQLite on every
    // page remount (measured: 1–3 s latency per round-trip in debug builds).
    // The partialize middleware already strips heavy fields before localStorage
    // persistence — only the in-memory store retains them.

    // Persisted display settings from store
    const {
        primaryMetric,
        leftSecondaryMetric,
        secondaryMetric,
        tertiaryMetric,
        showLegend,
        showControls,
        showTouchPoints,
        viscosityThreshold,
        showTargetTime,
        targetTime,
    } = displaySettings;

    const update = useCallback((patch: Partial<typeof displaySettings>) => updateDisplaySettings(patch), [updateDisplaySettings]);

    // Local state for ephemeral UI only
    const [isSelectorOpen, setIsSelectorOpen] = useState(false);
    const [limitWarning, setLimitWarning] = useState(false);
    const [duplicateWarning, setDuplicateWarning] = useState(false);
    const warningTimerRef = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
    // Clean up warning timer on unmount
    useEffect(() => () => clearTimeout(warningTimerRef.current), []);

    const handleAddExperiment = (experiment: Experiment) => {
        if (isInComparison(experiment.id)) {
            setDuplicateWarning(true);
            clearTimeout(warningTimerRef.current);
            warningTimerRef.current = setTimeout(() => setDuplicateWarning(false), 3000);
            return;
        }

        const added = addExperiment(experiment);
        if (!added) {
            // Show limit warning
            setLimitWarning(true);
            clearTimeout(warningTimerRef.current);
            warningTimerRef.current = setTimeout(() => setLimitWarning(false), 3000);
        } else {
            setIsSelectorOpen(false);
        }
    };

    const isAtLimit = experiments.length >= maxExperiments;

    return (
        <div data-testid="ComparisonPageRoot" className="flex flex-col h-[calc(100vh-6rem)] bg-transparent text-slate-200">
            <main className="flex-1 min-h-0 w-full mx-auto px-2 py-2 flex flex-col gap-2">
                {/* Header & Controls */}
                <div className="flex-none flex flex-col gap-4 px-5">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <h2 className="text-xl font-medium text-white tracking-tight">Сравнение экспериментов</h2>
                            <button
                                onClick={() => update({ showControls: !showControls })}
                                className={`p-1.5 rounded-lg transition-colors ${showControls ? 'bg-blue-500/20 text-blue-400' : 'text-slate-600 hover:text-slate-400'}`}
                                title="Настройки осей"
                            >
                                <Settings2 className="w-4 h-4" />
                            </button>
                        </div>

                        {/* Experiment Chips */}
                        <div data-testid="SelectedExperimentsChips" className="flex flex-wrap items-center gap-2 justify-end">
                            {/* Counter Badge */}
                            <span className={`text-xs px-2 py-0.5 rounded-full ${isAtLimit ? 'bg-amber-500/20 text-amber-400 border border-amber-500/30' : 'bg-slate-800 text-slate-400'}`}>
                                {experiments.length}/{maxExperiments}
                            </span>

                            {experiments.map(exp => (
                                <ExperimentChip key={exp.id} name={exp.name} onRemove={() => removeExperiment(exp.id)} />
                            ))}

                            {/* Limit Warning Toast */}
                            {limitWarning && (
                                <div className="flex items-center gap-2 px-3 py-1.5 bg-amber-500/20 text-amber-400 rounded-full text-xs font-medium border border-amber-500/30 animate-pulse">
                                    <AlertCircle className="w-3.5 h-3.5" />
                                    Достигнут лимит ({maxExperiments} графиков)
                                </div>
                            )}

                            {/* Duplicate Warning Toast */}
                            {duplicateWarning && (
                                <div className="flex items-center gap-2 px-3 py-1.5 bg-blue-500/20 text-blue-400 rounded-full text-xs font-medium border border-blue-500/30 animate-pulse">
                                    <AlertCircle className="w-3.5 h-3.5" />
                                    Уже добавлено
                                </div>
                            )}

                            <button
                                onClick={() => setIsSelectorOpen(true)}
                                disabled={isAtLimit}
                                data-testid="OpenExperimentSelectorButton"
                                className={`flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-medium transition-colors border ${isAtLimit
                                    ? 'bg-slate-800/50 text-slate-500 border-slate-700 cursor-not-allowed'
                                    : 'bg-blue-600/10 text-blue-400 hover:bg-blue-600/20 border-blue-500/20 hover:border-blue-500/30'
                                    }`}
                                title={isAtLimit ? `Лимит: ${maxExperiments} графиков` : 'Добавить тест'}
                            >
                                <Plus className="w-3.5 h-3.5" />
                                {isAtLimit ? 'Лимит' : 'Добавить тест'}
                            </button>
                        </div>
                    </div>

                    {/* Axis Toolbar */}
                    <div className={`border-b border-slate-800/50 pb-2 transition-[max-height,opacity] duration-300 ease-in-out overflow-hidden ${showControls ? 'max-h-20 opacity-100' : 'max-h-0 opacity-0'}`}>
                        <div className="flex items-center gap-6 overflow-x-auto py-1">
                            <AxisSelector
                                label="Слева 1"
                                value={primaryMetric}
                                onChange={(val) => {
                                    const patch: Record<string, string> = { primaryMetric: val };
                                    if (leftSecondaryMetric === val) patch.leftSecondaryMetric = 'none';
                                    if (secondaryMetric === val) patch.secondaryMetric = 'none';
                                    if (tertiaryMetric === val) patch.tertiaryMetric = 'none';
                                    update(patch);
                                }}
                                options={METRICS}
                                color="blue"
                            />
                            <AxisSelector
                                label="Слева 2"
                                value={leftSecondaryMetric}
                                onChange={(val) => {
                                    const patch: Record<string, string> = { leftSecondaryMetric: val };
                                    if (secondaryMetric === val) patch.secondaryMetric = 'none';
                                    if (tertiaryMetric === val) patch.tertiaryMetric = 'none';
                                    update(patch);
                                }}
                                options={METRICS}
                                excludeValues={[primaryMetric]}
                                color="purple"
                                allowNone
                            />

                            <div className="h-8 w-px bg-slate-800 mx-2"></div>

                            <AxisSelector
                                label="Справа 1"
                                value={secondaryMetric}
                                onChange={(val) => {
                                    const patch: Record<string, string> = { secondaryMetric: val };
                                    if (leftSecondaryMetric === val) patch.leftSecondaryMetric = 'none';
                                    if (tertiaryMetric === val) patch.tertiaryMetric = 'none';
                                    update(patch);
                                }}
                                options={METRICS}
                                excludeValues={[primaryMetric, leftSecondaryMetric]}
                                color="slate"
                                allowNone
                            />
                            <AxisSelector
                                label="Справа 2"
                                value={tertiaryMetric}
                                onChange={(val) => {
                                    const patch: Record<string, string> = { tertiaryMetric: val };
                                    if (leftSecondaryMetric === val) patch.leftSecondaryMetric = 'none';
                                    if (secondaryMetric === val) patch.secondaryMetric = 'none';
                                    update(patch);
                                }}
                                options={METRICS}
                                excludeValues={[primaryMetric, leftSecondaryMetric, secondaryMetric]}
                                color="amber"
                                allowNone
                            />

                            <div className="h-8 w-px bg-slate-800 mx-2"></div>

                            <ViscosityThresholdControl
                                enabled={showTouchPoints}
                                onEnabledChange={(v) => update({ showTouchPoints: v })}
                                threshold={viscosityThreshold}
                                onThresholdChange={(v) => update({ viscosityThreshold: v })}
                                showTargetTime={showTargetTime}
                                onShowTargetTimeChange={(v) => update({ showTargetTime: v })}
                                targetTime={targetTime}
                                onTargetTimeChange={(v) => update({ targetTime: v })}
                            />

                            <div className="flex-1"></div>

                            <LegendToggle checked={showLegend} onChange={(v) => update({ showLegend: v })} />
                        </div>
                    </div>
                </div>

                {/* Chart Area */}
                <div data-testid="ComparisonChartContainer" className="flex-1 relative bg-slate-900/50 border border-slate-800/60 rounded-2xl shadow-xl overflow-hidden p-1">
                    {experiments.length > 0 ? (
                        <div className="w-full h-full">
                            <ComparisonChart
                                experiments={experiments}
                                primaryMetric={primaryMetric}
                                leftSecondaryMetric={leftSecondaryMetric}
                                secondaryMetric={secondaryMetric}
                                tertiaryMetric={tertiaryMetric}
                                showLegend={showLegend}
                                showTouchPoints={showTouchPoints}
                                viscosityThreshold={viscosityThreshold}
                                showTargetTime={showTargetTime}
                                targetTime={targetTime}
                            />
                        </div>
                    ) : (
                        <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-500 bg-slate-900/20">
                            <Layers className="w-16 h-16 mb-4 opacity-20" />
                            <p className="text-base font-medium text-slate-400">Выберите тесты для сравнения</p>
                            <p className="text-sm text-slate-600 mt-1">Добавьте хотя бы один эксперимент</p>
                            <button
                                onClick={() => setIsSelectorOpen(true)}
                                data-testid="OpenExperimentSelectorButtonEmpty"
                                className="mt-6 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-500 transition-colors shadow-lg shadow-blue-500/20"
                            >
                                Открыть библиотеку
                            </button>
                        </div>
                    )}
                </div>
            </main>

            <ComparisonSelector isOpen={isSelectorOpen} onClose={() => setIsSelectorOpen(false)} onSelect={handleAddExperiment} />
        </div>
    );
}

/**
 * useExperimentSave Hook
 * 
 * Логика сохранения эксперимента с поддержкой перезаписи и toast уведомлений
 */

import { useState, useCallback } from 'react';
import type { ExperimentSavePayload } from '@/types';
import type { ParseResult } from '@/lib/store/experiment-data-store';
import { saveExperiment } from '@/lib/experiments/client';
import { useToast } from '@/hooks/useToast';

interface UseExperimentSaveOptions {
    parseResult: ParseResult | null;
    isDemo: boolean;
    canSaveExperiment: () => { allowed: boolean; message?: string };
    refreshExperimentsCount: () => void;
    setWaterSource: (source: string) => void;
    setWaterParams: (params: Record<string, unknown>) => void;
    setRecipe: (recipe: Array<{
        abbreviation: string;
        concentration: number;
        unit: string;
        reagentId?: string;
        reagentName?: string;
        batchNumber?: string;
        productionDate?: Date;
        category?: string;
    }>) => void;
    updateMetadata: (metadata: Record<string, unknown>) => void;
}

export function useExperimentSave({
    parseResult,
    isDemo,
    canSaveExperiment,
    refreshExperimentsCount,
    setWaterSource,
    setWaterParams,
    setRecipe,
    updateMetadata
}: UseExperimentSaveOptions) {
    const [isSaving, setIsSaving] = useState(false);
    const [showSaveDialog, setShowSaveDialog] = useState(false);
    const [pendingOverwritePayload, setPendingOverwritePayload] = useState<ExperimentSavePayload | null>(null);
    const { showToast } = useToast();

    const handleSave = useCallback(async (payload: ExperimentSavePayload) => {
        // Проверить лимит Demo перед сохранением
        if (!payload.overwrite) {
            const saveCheck = canSaveExperiment();
            if (!saveCheck.allowed) {
                showToast(saveCheck.message || 'Сохранение невозможно', 'error', 5000);
                return;
            }
        }

        setIsSaving(true);
        try {
            const result = await saveExperiment(payload);

            if (!result.success) {
                if (result.code === 'DUPLICATE_ENTRY') {
                    setPendingOverwritePayload(payload);
                    return;
                }
                throw new Error(result.error || 'Ошибка сохранения');
            }

            setWaterSource(payload.waterSource);
            if (payload.waterParams) setWaterParams(payload.waterParams as unknown as Record<string, unknown>);
            if (payload.reagents && payload.reagents.length > 0) {
                setRecipe(payload.reagents.map(r => ({
                    abbreviation: r.reagentName || '',
                    concentration: r.concentration,
                    unit: r.unit,
                    reagentId: r.reagentId,
                    reagentName: r.reagentName,
                    batchNumber: r.batchNumber,
                    productionDate: r.productionDate,
                    category: r.category
                })));
            }

            // Update metadata with saved values
            updateMetadata({
                filenameMetadata: {
                    ...(parseResult?.metadata?.filenameMetadata || {}),
                    fieldName: payload.fieldName,
                    wellNumber: payload.wellNumber,
                    operatorName: payload.operatorName,
                    testId: payload.testId || payload.name,
                    waterSource: payload.waterSource
                }
            });

            setShowSaveDialog(false);
            setPendingOverwritePayload(null);

            // Обновить счётчик экспериментов
            if (!payload.overwrite && isDemo) {
                refreshExperimentsCount();
            }

            showToast(
                payload.overwrite ? 'Эксперимент обновлён' : 'Эксперимент успешно сохранён',
                'success',
            );
        } catch (err) {
            // Tauri invoke rejects with a plain string (not an Error object).
            const message = err instanceof Error
                ? err.message
                : typeof err === 'string'
                    ? err
                    : 'Ошибка при сохранении';
            showToast(message, 'error');
        } finally {
            setIsSaving(false);
        }
    }, [parseResult, isDemo, canSaveExperiment, refreshExperimentsCount, setWaterSource, setWaterParams, setRecipe, updateMetadata]);

    const confirmOverwrite = useCallback(() => {
        if (pendingOverwritePayload) {
            handleSave({ ...pendingOverwritePayload, overwrite: true });
        }
    }, [pendingOverwritePayload, handleSave]);

    const cancelOverwrite = useCallback(() => {
        setPendingOverwritePayload(null);
        setIsSaving(false);
    }, []);

    return {
        isSaving,
        showSaveDialog,
        setShowSaveDialog,
        pendingOverwritePayload,
        handleSave,
        confirmOverwrite,
        cancelOverwrite
    };
}

import { logger as clientLogger } from '@/lib/client-logger';

import { Plus, Trash2 } from 'lucide-react';
import { Logo } from '@/components/ui/logo';
import React, { useState, useEffect, useCallback } from 'react';
import { useCatalogStore } from '@/lib/store/catalog-store';

export interface RecipeComponent {
    abbreviation: string;
    concentration: number;
    unit: string;
    category?: string;
    reagentId?: string;
    reagentName?: string;
    batchNumber?: string;
    productionDate?: Date;
}

interface ReagentCatalogItem {
    id: string;
    name: string;
    category: string;
}

interface RecipePanelProps {
    recipe: RecipeComponent[];
    onRecipeChange?: (recipe: RecipeComponent[]) => void;
}

// Category translations
const CATEGORY_LABELS: Record<string, string> = {
    'Gelling Agent': 'Гелеобразователь',
    'Crosslinker': 'Сшиватель',
    'Breaker': 'Деструктор',
    'Buffer': 'Буфер pH',
    'Stabilizer': 'Стабилизатор',
    'Clay Control': 'Ингибитор глин',
    'Friction Reducer': 'Понизитель трения',
    'Viscosifier': 'Загуститель',
    'Biocide': 'Биоцид',
    'Surfactant': 'ПАВ',
};

export const RecipePanel = React.memo(function RecipePanel({ recipe: externalRecipe, onRecipeChange }: RecipePanelProps) {
    // Use external state directly if callback provided (controlled mode)
    // Otherwise, use internal state (uncontrolled mode)
    const [internalRecipe, setInternalRecipe] = useState<RecipeComponent[]>(externalRecipe || []);

    // Controlled vs uncontrolled pattern
    const recipe = onRecipeChange ? externalRecipe : internalRecipe;
    const setRecipe = onRecipeChange || setInternalRecipe;

    const reagentCatalog = useCatalogStore(s => s.reagents) as ReagentCatalogItem[];
    const isLoading = useCatalogStore(s => s.reagentsLoading);
    const fetchReagentsCatalog = useCatalogStore(s => s.fetchReagents);

    // Load reagent catalog (shared store deduplicates)
    useEffect(() => {
        fetchReagentsCatalog();
    }, [fetchReagentsCatalog]);

    // Group reagents by category
    const groupedReagents = reagentCatalog.reduce<Record<string, ReagentCatalogItem[]>>((acc, r) => {
        if (!acc[r.category]) acc[r.category] = [];
        acc[r.category].push(r);
        return acc;
    }, {});

    // Update recipe
    const updateRecipe = useCallback((newRecipe: RecipeComponent[]) => {
        setRecipe(newRecipe);
    }, [setRecipe]);

    // Update single row
    const updateRow = useCallback((idx: number, field: keyof RecipeComponent, value: unknown) => {
        const newRecipe = [...recipe];
        newRecipe[idx] = { ...newRecipe[idx], [field]: value };
        updateRecipe(newRecipe);
    }, [recipe, updateRecipe]);

    // Add new row
    const addRow = useCallback(() => {
        updateRecipe([...recipe, {
            abbreviation: '',
            concentration: 0,
            unit: 'kg/m3',
        }]);
    }, [recipe, updateRecipe]);

    // Remove row
    const removeRow = useCallback((idx: number) => {
        updateRecipe(recipe.filter((_, i) => i !== idx));
    }, [recipe, updateRecipe]);

    // Handle reagent select change
    const handleReagentChange = useCallback((idx: number, reagentId: string) => {
        const reagent = reagentCatalog.find(r => r.id === reagentId);
        const newRecipe = [...recipe];
        newRecipe[idx] = {
            ...newRecipe[idx],
            reagentId,
            reagentName: reagent?.name || '',
            abbreviation: reagent?.name || newRecipe[idx].abbreviation,
            category: reagent?.category,
        };
        updateRecipe(newRecipe);
    }, [recipe, reagentCatalog, updateRecipe]);

    if (!recipe || recipe.length === 0) {
        return (
            <div className="bg-slate-900/50 border border-slate-700 rounded-xl p-6">
                <div className="flex items-center gap-3 mb-4">
                    <div className="p-2 bg-gradient-to-br from-blue-600 to-purple-600 rounded-lg">
                        <Logo className="w-5 h-5" />
                    </div>
                    <h3 className="font-semibold text-white">Рецептура</h3>
                </div>
                <p className="text-slate-400 text-sm text-center py-4">
                    Нет данных о рецептуре
                </p>
                <button
                    onClick={addRow}
                    data-testid="AddReagentButton"
                    className="w-full py-2 bg-cyan-600 hover:bg-cyan-500 text-white rounded-lg text-sm transition-colors flex items-center justify-center gap-2"
                >
                    <Plus className="w-4 h-4" />
                    Добавить реагент
                </button>
            </div>
        );
    }

    return (
        <div className="bg-slate-900/50 border border-slate-700 rounded-xl overflow-hidden">
            {/* Header */}
            <div className="px-4 py-3 border-b border-slate-700 flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-gradient-to-br from-blue-600 to-purple-600 rounded-lg">
                        <Logo className="w-5 h-5" />
                    </div>
                    <div>
                        <h3 className="font-semibold text-white">Рецептура</h3>
                        <p className="text-xs text-slate-400">{recipe.length} компонентов</p>
                    </div>
                </div>
                <button
                    onClick={addRow}
                    data-testid="AddReagentButton"
                    className="flex items-center gap-1 px-3 py-1 bg-cyan-600 hover:bg-cyan-500 text-white rounded text-sm transition-colors"
                >
                    <Plus className="w-4 h-4" />
                    Добавить
                </button>
            </div>

            {/* Table */}
            <table className="w-full">
                <thead>
                    <tr className="bg-slate-800/50 text-xs text-slate-400 font-medium">
                        <th className="px-3 py-2 text-left w-[30%]">Реагент</th>
                        <th className="px-3 py-2 text-left w-[15%]">Концентрация</th>
                        <th className="px-3 py-2 text-left w-[10%]">Ед.</th>
                        <th className="px-3 py-2 text-left w-[18%]">№ партии</th>
                        <th className="px-3 py-2 text-left w-[20%]">Дата пр-ва</th>
                        <th className="px-3 py-2 w-[7%]"></th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-slate-700/50">
                    {recipe.map((row, idx) => (
                        <tr key={idx} className="hover:bg-slate-800/30">
                            {/* Reagent */}
                            <td className="px-3 py-2 align-top">
                                {isLoading ? (
                                    <div className="animate-pulse bg-slate-700 h-8 rounded"></div>
                                ) : (
                                    <div>
                                        <select
                                            value={row.reagentId || ''}
                                            onChange={(e) => handleReagentChange(idx, e.target.value)}
                                            className="w-full bg-slate-700 border border-slate-600 rounded px-2 py-1.5 text-white text-sm focus:outline-none focus:ring-1 focus:ring-cyan-500"
                                        >
                                            <option value="">{row.abbreviation || 'Выберите...'}</option>
                                            {Object.entries(groupedReagents)
                                                .sort(([a], [b]) => a.localeCompare(b))
                                                .map(([category, items]) => (
                                                    <optgroup key={category} label={CATEGORY_LABELS[category] || category}>
