                                    onChange={(e) => updateRow(idx, 'productionDate', e.target.value ? new Date(e.target.value) : undefined)}
                                    data-testid="ReagentProductionDatePicker"
                                    className="w-full bg-slate-700 border border-slate-600 rounded px-2 py-1.5 text-white text-sm focus:outline-none focus:ring-1 focus:ring-cyan-500"
                                />
                            </td>

                            {/* Remove button */}
                            <td className="px-3 py-2 text-center align-top">
                                <button
                                    onClick={() => removeRow(idx)}
                                    data-testid="RemoveReagentButton"
                                    className="p-1.5 text-red-400 hover:text-red-300 transition-colors"
                                    title="Удалить"
                                    aria-label="Удалить компонент"
                                >
                                    <Trash2 className="w-4 h-4" />
                                </button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
});

import { logger as clientLogger } from '@/lib/client-logger';

import { Droplets } from 'lucide-react';
import React, { useState, useEffect } from 'react';
import { useCatalogStore } from '@/lib/store/catalog-store';

export interface WaterParams {
    ph?: number;
    fe?: number;    // Iron in mg/L
    ca?: number;    // Calcium in mg/L
    mg?: number;    // Magnesium in mg/L
    cl?: number;    // Chloride in mg/L
    so4?: number;   // Sulfate in mg/L
    hco3?: number;  // Bicarbonate in mg/L
    salinity?: number; // Salinity in mg/L
    hardness?: number; // Hardness in mg/L
}

interface WaterAnalysisPanelProps {
    waterSource?: string;
    waterParams?: WaterParams;
    onWaterSourceChange?: (source: string) => void;
    onParamsChange?: (params: WaterParams) => void;
}

// Component parameter definitions
const WATER_COMPONENTS = [
    { key: 'ph', label: 'pH', unit: '', step: '0.1' },
    { key: 'fe', label: 'Fe', unit: 'мг/л', step: '0.1' },
    { key: 'ca', label: 'Ca', unit: 'мг/л', step: '1' },
    { key: 'mg', label: 'Mg', unit: 'мг/л', step: '1' },
    { key: 'cl', label: 'Cl', unit: 'мг/л', step: '1' },
    { key: 'so4', label: 'SO₄', unit: 'мг/л', step: '1' },
    { key: 'hco3', label: 'HCO₃', unit: 'мг/л', step: '1' },
] as const;

export const WaterAnalysisPanel = React.memo(function WaterAnalysisPanel({
    waterSource: externalWaterSource,
    waterParams: externalWaterParams,
    onWaterSourceChange,
    onParamsChange
}: WaterAnalysisPanelProps) {
    // Controlled vs uncontrolled pattern
    const [internalWaterSource, setInternalWaterSource] = useState(externalWaterSource || '');
    const [internalWaterParams, setInternalWaterParams] = useState<WaterParams>(externalWaterParams || {
        ph: 7.0, fe: 0, ca: 0, mg: 0, cl: 0, so4: 0, hco3: 0
    });

    // Use external state if callbacks provided (controlled mode)
    const waterSource = onWaterSourceChange ? (externalWaterSource || '') : internalWaterSource;
    const waterParams = onParamsChange ? (externalWaterParams || {}) : internalWaterParams;

    const waterSourceSuggestions = useCatalogStore(s => s.waterSources);
    const fetchCatalogWaterSources = useCatalogStore(s => s.fetchWaterSources);

    // Load water source suggestions (shared store deduplicates)
    useEffect(() => {
        fetchCatalogWaterSources();
    }, [fetchCatalogWaterSources]);

    // Handle water source change
    const handleWaterSourceChange = (value: string) => {
        if (onWaterSourceChange) {
            onWaterSourceChange(value);
        } else {
            setInternalWaterSource(value);
        }
    };

    // Handle params change
    const handleParamChange = (key: string, value: number | undefined) => {
        const newParams = { ...waterParams, [key]: value };
        if (onParamsChange) {
            onParamsChange(newParams);
        } else {
            setInternalWaterParams(newParams);
        }
    };

    return (
        <div className="bg-slate-900/50 border border-slate-700 rounded-xl overflow-hidden">
            {/* Header */}
            <div className="px-4 py-3 border-b border-slate-700 flex items-center gap-3">
                <div className="p-2 bg-gradient-to-br from-cyan-600 to-blue-600 rounded-lg">
                    <Droplets className="w-5 h-5 text-white" />
                </div>
                <div>
                    <h3 className="font-semibold text-white">Анализ воды</h3>
                    <p className="text-xs text-slate-400">7-компонентный анализ</p>
                </div>
            </div>

            {/* Content */}
            <div className="p-4 space-y-4">
                {/* Water source input */}
                <div>
                    <label className="block text-sm text-slate-400 mb-1">
                        Источник воды <span className="text-red-400">*</span>
                    </label>
                    <input
                        type="text"
                        list="water-sources-list"
                        value={waterSource}
                        onChange={(e) => handleWaterSourceChange(e.target.value)}
                        className={`w-full bg-slate-700 border rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:ring-2 focus:ring-cyan-500 ${!waterSource.trim() ? 'border-red-500/50' : 'border-slate-600'
                            }`}
                        placeholder="Озеро Самотлор, Пластовая вода скв. 123..."
                    />
                    <datalist id="water-sources-list">
                        {waterSourceSuggestions.map((source, idx) => (
                            <option key={idx} value={source} />
                        ))}
                    </datalist>
                </div>

                {/* 7-component analysis grid */}
                <div>
                    <label className="block text-sm text-slate-400 mb-2">Показатели</label>
                    <div className="grid grid-cols-7 gap-2">
                        {WATER_COMPONENTS.map((comp) => (
                            <div key={comp.key}>
                                <label className="block text-xs text-slate-400 mb-1 text-center">{comp.label}</label>
                                <input
                                    type="number"
                                    step={comp.step}
                                    value={waterParams[comp.key as keyof WaterParams] ?? ''}
                                    onChange={(e) => {
                                        const val = e.target.value === '' ? undefined : parseFloat(e.target.value);
                                        handleParamChange(comp.key, val);
                                    }}
                                    className="w-full bg-slate-700 border border-slate-600 rounded px-2 py-1.5 text-white text-sm text-center focus:outline-none focus:ring-1 focus:ring-cyan-500"
                                    placeholder="—"
                                />
                                {comp.unit && (
                                    <span className="block text-xs text-slate-500 text-center mt-0.5">{comp.unit}</span>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );
});

import { logger as clientLogger } from '@/lib/client-logger';

import { useState, useEffect, useRef, useCallback } from 'react';
import { Search, X, Loader2, FolderOpen, Upload } from 'lucide-react';
import { format } from 'date-fns';
import { useFocusTrap } from '@/hooks/useFocusTrap';
import { ru } from 'date-fns/locale';
import type { Experiment } from '@/types';
import { listExperiments, getExperimentById } from '@/lib/experiments/client';
import { parseRheologyFile } from '@/lib/parsing/client';
import { rawPointsFromParseResult } from '@/lib/utils/columnar';

interface ComparisonSelectorProps {
    isOpen: boolean;
    onClose: () => void;
    onSelect: (experiment: Experiment) => void;
}

// Module-level cache — survives component unmount/remount when isOpen toggles.
// The selector returns `null` when closed, destroying all useRef/useState.
// Without this, the experiment-list IPC fires on every open (~300-500 ms).
let _listCache: { search: string; ts: number; experiments: Experiment[] } = {
    search: '', ts: 0, experiments: [],
};
const CACHE_TTL_MS = 5_000;

export function ComparisonSelector({ isOpen, onClose, onSelect }: ComparisonSelectorProps) {
    const focusTrapRef = useFocusTrap<HTMLDivElement>(isOpen);
    const [activeTab, setActiveTab] = useState<'library' | 'file'>('library');
    const [search, setSearch] = useState('');
    const [debouncedSearch, setDebouncedSearch] = useState('');
    const [experiments, setExperiments] = useState<Experiment[]>(() =>
        // Seed from module cache to avoid blank list on re-open
        _listCache.search === '' && _listCache.experiments.length > 0
            ? _listCache.experiments
            : []
    );
    const [isLoading, setIsLoading] = useState(false);
    const [loadingId, setLoadingId] = useState<string | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [parseError, setParseError] = useState<string | null>(null);
    const [isDragging, setIsDragging] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        const timer = setTimeout(() => {
            setDebouncedSearch(search);
        }, 300);
        return () => clearTimeout(timer);
    }, [search]);

    const fetchExperiments = useCallback(async (cancelled: { current: boolean }) => {
        setIsLoading(true);
        try {
            const data = await listExperiments({
                limit: 20,
                fieldName: debouncedSearch // Simple search by field name for now
            });
            if (!cancelled.current && data.experiments) {
                const exps = data.experiments as unknown as Experiment[];
                setExperiments(exps);
                _listCache = { search: debouncedSearch, ts: Date.now(), experiments: exps };
            }
        } catch (err) {
            if (!cancelled.current) clientLogger.error('Failed to fetch experiments:', err);
        } finally {
            if (!cancelled.current) setIsLoading(false);
        }
    }, [debouncedSearch]);

    useEffect(() => {
        if (!isOpen) return;
        // Skip IPC round-trip when re-opening quickly with the same search query.
        // The module-level _listCache survives unmount so repeated opens in the
        // same 5-second window are instant.
        const cache = _listCache;
        if (
            cache.search === debouncedSearch &&
            Date.now() - cache.ts < CACHE_TTL_MS &&
            cache.experiments.length > 0
        ) {
            setExperiments(cache.experiments);
            return;
        }
        const cancelled = { current: false };
        fetchExperiments(cancelled);
        return () => { cancelled.current = true; };
    }, [isOpen, fetchExperiments]);

    // Load full experiment (with rawPoints) before adding to comparison
    const handleSelect = useCallback(async (exp: Experiment) => {
        setLoadingId(exp.id);
        try {
            const response = await getExperimentById(exp.id);
            if (response.success && response.experiment) {
                onSelect(response.experiment as unknown as Experiment);
            } else {
                clientLogger.error('Failed to load full experiment:', response.error);
            }
        } catch (err) {
            clientLogger.error('Failed to fetch experiment for comparison:', err);
        } finally {
            setLoadingId(null);
        }
    }, [onSelect]);

    const handleFileSelect = useCallback(async (file: File) => {
        setIsParsing(true);
        setParseError(null);
        try {
            const parseResult = await parseRheologyFile(file);
            const rawPoints = rawPointsFromParseResult(parseResult);
            const syntheticExp: Experiment = {
                id: `file-${Date.now()}-${Math.random().toString(36).slice(2)}`,
                name: file.name.replace(/\.[^/.]+$/, ''),
                testDate: new Date(),
                fluidType: 'Linear',
                instrumentType: 'Unknown',
                rawPoints,
            } as unknown as Experiment;
            onSelect(syntheticExp);
        } catch (err) {
            clientLogger.error('Failed to parse file for comparison:', err);
            setParseError(err instanceof Error ? err.message : String(err));
        } finally {
            setIsParsing(false);
        }
    }, [onSelect]);

    const handleInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) handleFileSelect(file);
        // Reset so the same file can be re-selected
        e.target.value = '';
    }, [handleFileSelect]);

    const handleDrop = useCallback((e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault();
        setIsDragging(false);
        const file = e.dataTransfer.files?.[0];
        if (file) handleFileSelect(file);
    }, [handleFileSelect]);

    // Close on Escape key
    useEffect(() => {
        if (!isOpen) return;
        const handleKey = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
        document.addEventListener('keydown', handleKey);
        return () => document.removeEventListener('keydown', handleKey);
    }, [isOpen, onClose]);

    if (!isOpen) return null;

    return (
        <div ref={focusTrapRef} data-testid="ComparisonSelectorOverlay" role="dialog" aria-modal="true" className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4" onClick={e => { if (e.target === e.currentTarget) onClose(); }}>
            <div
                data-testid="ComparisonSelectorDialog"
                aria-labelledby="comparison-selector-title"
                className="bg-slate-800 rounded-xl shadow-2xl max-w-2xl w-full max-h-[80vh] flex flex-col"
            >
                <div className="p-4 border-b border-slate-700 flex items-center justify-between">
                    <h3 id="comparison-selector-title" className="text-lg font-medium text-white">Выберите тест для сравнения</h3>
                    <button data-testid="ComparisonSelectorCloseButton" onClick={onClose} aria-label="Закрыть" className="text-slate-400 hover:text-white">
                        <X className="w-5 h-5" />
                    </button>
                </div>

                {/* Tab switcher */}
                <div className="flex border-b border-slate-700">
                    <button
                        onClick={() => setActiveTab('library')}
                        className={`flex-1 py-2.5 text-sm font-medium transition-colors ${
                            activeTab === 'library'
                                ? 'text-blue-400 border-b-2 border-blue-400'
                                : 'text-slate-400 hover:text-slate-200'
                        }`}
                    >
                        Из библиотеки
                    </button>
                    <button
                        onClick={() => { setActiveTab('file'); setParseError(null); }}
                        className={`flex-1 py-2.5 text-sm font-medium transition-colors ${
                            activeTab === 'file'
                                ? 'text-blue-400 border-b-2 border-blue-400'
                                : 'text-slate-400 hover:text-slate-200'
                        }`}
                    >
                        Из файла
                    </button>
                </div>

                {activeTab === 'library' && (
                <div className="p-4 border-b border-slate-700">
                    <div className="relative">
                        <input
                            type="text"
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                            data-testid="ComparisonSelectorSearchInput"
                            className="w-full bg-slate-900 border border-slate-700 rounded-lg py-2 pl-10 pr-4 text-white focus:outline-none focus:border-blue-500"
                            placeholder="Поиск по названию или месторождению..."
                        />
                        <Search className="w-4 h-4 text-slate-500 absolute left-3 top-3" />
                    </div>
                </div>
                )}

                <div className="flex-1 overflow-y-auto p-2">
                    {activeTab === 'file' ? (
                        <div className="p-4 flex flex-col items-center gap-4">
                            <input
                                ref={fileInputRef}
                                type="file"
                                accept=".xlsx,.xls,.csv,.txt"
                                className="hidden"
                                onChange={handleInputChange}
                            />
                            <div
                                onDragOver={e => { e.preventDefault(); setIsDragging(true); }}
                                onDragLeave={() => setIsDragging(false)}
                                onDrop={handleDrop}
                                onClick={() => !isParsing && fileInputRef.current?.click()}
                                className={`w-full border-2 border-dashed rounded-xl p-10 text-center cursor-pointer transition-colors ${
                                    isDragging
                                        ? 'border-blue-400 bg-blue-500/10'
                                        : 'border-slate-600 hover:border-slate-400 hover:bg-slate-700/30'
                                }`}
                            >
                                {isParsing ? (
                                    <div className="flex flex-col items-center gap-3 text-slate-400">
                                        <Loader2 className="w-8 h-8 animate-spin text-blue-500" />
                                        <span>Обработка файла...</span>
                                    </div>
                                ) : (
                                    <div className="flex flex-col items-center gap-3 text-slate-400">
                                        <Upload className="w-8 h-8" />
                                        <span className="text-sm">Перетащите файл сюда или нажмите для выбора</span>
                                        <span className="text-xs text-slate-500">Поддерживаемые форматы: xlsx, xls, csv, txt</span>
                                    </div>
                                )}
                            </div>
                            <button
                                onClick={() => !isParsing && fileInputRef.current?.click()}
                                disabled={isParsing}
                                className="flex items-center gap-2 px-4 py-2 rounded-lg bg-slate-700 hover:bg-slate-600 text-sm text-white disabled:opacity-50 transition-colors"
                            >
                                <FolderOpen className="w-4 h-4" />
                                Выбрать файл
                            </button>
                            {parseError && (
                                <div className="w-full rounded-lg bg-red-500/10 border border-red-500/30 p-3 text-sm text-red-400">
                                    {parseError}
                                </div>
                            )}
                        </div>
                    ) : isLoading ? (
                        <div className="flex justify-center py-10">
                            <Loader2 className="w-6 h-6 text-blue-500 animate-spin" />
                        </div>
                    ) : (
                        <div className="space-y-2">
                            {experiments.map(exp => (
                                <div key={exp.id} data-testid="AddExperimentToComparison">
                                    <button
                                        onClick={() => handleSelect(exp)}
                                        disabled={loadingId === exp.id}
                                        data-testid="ComparisonSelectorExperimentButton"
                                        className="w-full text-left p-3 rounded-lg hover:bg-slate-700/50 transition-colors border border-transparent hover:border-slate-600 group disabled:opacity-50"
                                    >
                                        <div className="flex justify-between items-start">
                                            <span className="font-medium text-white group-hover:text-blue-400 transition-colors">
                                                {exp.name}
                                            </span>
                                            <span className="text-xs text-slate-500">
                                                {format(new Date(exp.testDate), 'dd MMM yyyy', { locale: ru })}
                                            </span>
                                        </div>
                                        <div className="flex gap-3 mt-1 text-xs text-slate-400">
                                            <span>{exp.fluidType === 'Crosslinked' ? 'Сшитый' : 'Линейный'}</span>
                                            <span>•</span>
                                            <span>{exp.instrumentType}</span>
                                            {exp.fieldName && (
                                                <>
                                                    <span>•</span>
                                                    <span>{exp.fieldName}</span>
                                                </>
                                            )}
                                        </div>
                                    </button>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

