    TEST_TYPES_BY_CATEGORY, TEST_TYPE_LABELS,
} from '@/lib/constants/test-types';

interface SaveExperimentDialogProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (payload: ExperimentSavePayload) => Promise<void>;
    analysisData: {
        filename: string;
        instrumentType: string;
        testDate: Date;
        fluidType: FluidType;
        testGroup: TestGroup;
        metrics: TestMetrics;
        /** Pre-expanded AoS — pass when already in memory. */
        rawPoints?: RheoPoint[];
        /** SoA alternative — converted lazily on submit to avoid holding two copies. */
        columnarData?: ColumnarData;
        calibration?: CalibrationData | null; // Added field
        geometry?: string;
        geometrySource?: string;
        testId?: string;
        prefilledName?: string;
        prefilledFieldName?: string;
        prefilledOperatorName?: string;
        prefilledWellNumber?: string;
        prefilledWaterSource?: string;
        prefilledWaterParams?: Partial<WaterParams>;
        prefilledRecipe?: Array<{
            abbreviation: string;
            concentration: number;
            unit: string;
            category?: string;
            reagentId?: string;
            reagentName?: string;
            batchNumber?: string;
            productionDate?: Date;
        }>;
        // V8 metadata round-trip
        parsedBy?: string;
        parseSource?: string;
        timeRangeMin?: number;
        timeRangeMax?: number;
        viscosityMin?: number;
        pressureMax?: number;
        extraFields?: Record<string, unknown>;
    };
}

export function SaveExperimentDialog({
    isOpen,
    onClose,
    onSave,
    analysisData
}: SaveExperimentDialogProps) {
    // ── Initialisation: form state, catalogs, smart-fill, prefill ────────────
    const {
        name, setName,
        fieldName, setFieldName,
        operatorName, setOperatorName,
        wellNumber, setWellNumber,
        testDate, setTestDate,
        waterSource, setWaterSource,
        waterParams, setWaterParams,
        reagents, setReagents,
        isLoading,
        recentReagentIds,
        waterSources,
        reagentCatalog,
        addToRecentReagents,
        handleSmartFill,
    } = useSaveDialogInit(isOpen, analysisData);

    // ── Submit state ──────────────────────────────────────────────────────────
    const [isSaving, setIsSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Handle save
    const handleSave = async () => {
        if (!name.trim()) { setError('Название теста обязательно'); return; }
        if (!fieldName.trim()) { setError('Месторождение обязательно'); return; }
        if (!operatorName.trim()) { setError('Оператор обязателен'); return; }
        if (!wellNumber.trim()) { setError('Номер скважины обязателен'); return; }
        if (!waterSource.trim()) { setError('Источник воды обязателен'); return; }

        setError(null);
        setIsSaving(true);

        // Debug: log geometry data being saved
        clientLogger.info('[SaveDialog] Saving with geometry:', {
            geometry: analysisData.geometry,
            geometrySource: analysisData.geometrySource
        });

        try {
            await onSave({
                name: name.trim(),
                fieldName: fieldName.trim(),
                operatorName: operatorName.trim(),
                wellNumber: wellNumber.trim(),
                testId: analysisData.testId,
                originalFilename: analysisData.filename,
                testDate,
                instrumentType: analysisData.instrumentType,
                geometry: analysisData.geometry,
                geometrySource: analysisData.geometrySource,
                waterSource: waterSource.trim(),
                waterParams,
                fluidType: fluidType,
                // Derive legacy testGroup from testType for backward compat
                testGroup: (testType === 'Hydration' ? 'Hydration' : 'Rheology') as TestGroup,
                testCategory,
                testType,
                metrics: analysisData.metrics,
                // Lazy AoS conversion: if only SoA columnarData was passed (no pre-expanded
                // rawPoints), convert here — inside the save handler — so the intermediate
                // AoS array is never held in memory during normal rendering.
                rawPoints: analysisData.rawPoints
                    ?? (analysisData.columnarData ? columnarToRawPoints(analysisData.columnarData) : []),
                calibration: analysisData.calibration, // Pass calibration data
                // V8 metadata round-trip
                parsedBy: analysisData.parsedBy,
                parseSource: analysisData.parseSource,
                timeRangeMin: analysisData.timeRangeMin,
                timeRangeMax: analysisData.timeRangeMax,
                viscosityMin: analysisData.viscosityMin,
                pressureMax: analysisData.pressureMax,
                extraFields: analysisData.extraFields,
                reagents: reagents.filter(r => r.reagentId).map(r => ({
                    reagentId: r.reagentId,
                    reagentName: r.reagentName,
                    concentration: r.concentration,
                    unit: r.unit,
                    batchNumber: r.batchNumber,
                    productionDate: r.productionDate
                }))
            });
            onClose();
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Ошибка сохранения');
        } finally {
            setIsSaving(false);
        }
    };

    if (!isOpen) return null;

    return (
        <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
            <DialogContent
                data-testid="SaveExperimentDialogWindow"
                className="max-w-4xl w-full max-h-[90vh] p-0 gap-0 bg-slate-800 border-slate-700 text-white sm:rounded-xl overflow-hidden flex flex-col"
            >
                <DialogHeader className="px-6 py-4 border-b border-slate-700 flex-shrink-0">
                    <DialogTitle className="text-xl font-semibold text-white">Сохранить эксперимент</DialogTitle>
                </DialogHeader>

                <div className="flex-1 overflow-y-auto p-6 space-y-6">
                    {isLoading && (
                        <div className="text-center py-4">
                            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-cyan-500 mx-auto"></div>
                            <p className="text-slate-400 mt-2">Загрузка последнего контекста...</p>
                        </div>
                    )}

                    {error && (
                        <div className="bg-red-500/20 border border-red-500 rounded-lg p-4 text-red-400">
                            {error}
                        </div>
                    )}

                    <ExperimentMetadataForm
                        name={name} setName={setName}
                        fieldName={fieldName} setFieldName={setFieldName}
                        operatorName={operatorName} setOperatorName={setOperatorName}
                        wellNumber={wellNumber} setWellNumber={setWellNumber}
                        testDate={testDate} setTestDate={setTestDate}
                        onSmartFill={handleSmartFill}
                    />

                    <WaterSourceSection
                        waterSource={waterSource} setWaterSource={setWaterSource}
                        waterParams={waterParams} setWaterParams={setWaterParams}
                        waterSources={waterSources}
                    />

                    <ReagentListEditor
                        reagents={reagents} setReagents={setReagents}
                        reagentCatalog={reagentCatalog}
                        recentReagentIds={recentReagentIds}
                        onReagentSelect={addToRecentReagents}
                    />

                    {/* Analysis Info — fluid type / test type are editable */}
                    <Card className="bg-slate-700/50 border-none">
                        <div className="p-4">
                            <h3 className="text-sm font-medium text-slate-400 mb-3">Информация об анализе</h3>
                            <div className="grid grid-cols-2 gap-4 text-sm mb-3">
                                <div><span className="text-slate-400">Файл:</span><span className="text-white ml-2">{analysisData.filename}</span></div>
                                <div><span className="text-slate-400">Прибор:</span><span className="text-white ml-2">{analysisData.instrumentType}</span></div>
                            </div>
                            <div className="grid grid-cols-3 gap-4">
                                {/* Fluid type */}
                                <div className="flex flex-col gap-1">
                                    <label className="text-xs text-slate-400">
                                        Тип жидкости
                                        {!fluidTypeUserSet && (
                                            <span className="ml-1 text-cyan-500/70">(авто)</span>
                                        )}
                                    </label>
                                    <Select value={fluidType} onValueChange={v => setFluidType(v as typeof FLUID_TYPES[number])}>
                                        <SelectTrigger className="bg-slate-800 border-slate-600 text-white h-8 text-xs">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent className="bg-slate-800 border-slate-600">
                                            {FLUID_TYPES.map(ft => (
                                                <SelectItem key={ft} value={ft} className="text-white hover:bg-slate-700 text-xs">
                                                    {FLUID_TYPE_SHORT[ft]}
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                                {/* Test category */}
                                <div className="flex flex-col gap-1">
                                    <label className="text-xs text-slate-400">Категория теста</label>
                                    <Select value={testCategory} onValueChange={v => setTestCategory(v as typeof TEST_CATEGORIES[number])}>
                                        <SelectTrigger className="bg-slate-800 border-slate-600 text-white h-8 text-xs">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent className="bg-slate-800 border-slate-600">
                                            {TEST_CATEGORIES.map(cat => (
                                                <SelectItem key={cat} value={cat} className="text-white hover:bg-slate-700 text-xs">
                                                    {TEST_CATEGORY_LABELS[cat]}
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                                {/* Test type — cascading, filtered by category */}
                                <div className="flex flex-col gap-1">
                                    <label className="text-xs text-slate-400">Тип теста</label>
                                    <Select value={testType} onValueChange={v => setTestType(v as typeof testType)}>
                                        <SelectTrigger className="bg-slate-800 border-slate-600 text-white h-8 text-xs">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent className="bg-slate-800 border-slate-600 max-h-56">
                                            {TEST_TYPES_BY_CATEGORY[testCategory].map(tt => (
                                                <SelectItem key={tt} value={tt} className="text-white hover:bg-slate-700 text-xs">
                                                    {TEST_TYPE_LABELS[tt]}
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                            </div>
                        </div>
                    </Card>
                </div>

                <DialogFooter className="px-6 py-4 border-t border-slate-700 flex-shrink-0 sm:justify-end gap-3 bg-slate-800">
                    <Button
                        variant="ghost"
                        onClick={onClose}
                        data-testid="SaveDialogCancelButton"
                        className="text-slate-400 hover:text-white hover:bg-slate-700"
                    >
                        Отмена
                    </Button>
                    <Button
                        onClick={handleSave}
                        data-testid="SaveDialogSaveButton"
                        disabled={isSaving || !name.trim() || !fieldName.trim() || !operatorName.trim() || !wellNumber.trim() || !waterSource.trim()}
                        className={isSaving || !name.trim() || !fieldName.trim() || !operatorName.trim() || !wellNumber.trim() || !waterSource.trim()
                            ? 'bg-slate-600 text-slate-400 cursor-not-allowed hover:bg-slate-600'
                            : 'bg-cyan-600 hover:bg-cyan-500 text-white'
                        }
                    >
                        {isSaving ? 'Сохранение...' : 'Сохранить'}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

import { logger as clientLogger } from '@/lib/client-logger';

import { useState, useEffect, useMemo, memo, useRef } from 'react';
import { Plus, Pencil, Trash2, Beaker, Search, ChevronDown, Loader2, AlertTriangle, Eye } from 'lucide-react';
import { useVirtualizer } from '@tanstack/react-virtual';
import { useFocusTrap } from '@/hooks/useFocusTrap';
import {
    createReagent,
    deleteReagent,
    updateReagent
} from '@/lib/reagents/client';
import { useCatalogStore } from '@/lib/store/catalog-store';
import { ReagentDetailDrawer, CATEGORIES, type Reagent } from './reagent-detail-drawer';
import { ReagentFormModal } from './reagent-form-modal';

type FlatItem =
    | { type: 'header'; group: { category: { value: string; label: string }; items: Reagent[] } }
    | { type: 'row'; group: { category: { value: string; label: string }; items: Reagent[] }; reagent: Reagent };

/** Virtualize the list only when the catalog grows beyond this threshold. */
const VIRTUAL_THRESHOLD = 50;

function ReagentsManagerComponent() {
    const reagents = useCatalogStore(s => s.reagents) as Reagent[];
    const isLoading = useCatalogStore(s => s.reagentsLoading);
    const fetchReagents = useCatalogStore(s => s.fetchReagents);
    const invalidateReagents = useCatalogStore(s => s.invalidateReagents);
    const [searchQuery, setSearchQuery] = useState('');
    const [categoryFilter, setCategoryFilter] = useState('');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingReagent, setEditingReagent] = useState<Reagent | null>(null);
    const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);
    const [detailReagent, setDetailReagent] = useState<Reagent | null>(null);
    const [error, setError] = useState<string | null>(null);
    const deleteFocusTrapRef = useFocusTrap<HTMLDivElement>(!!deleteConfirm);

    // Fetch reagents (shared store deduplicates)
    useEffect(() => {
        fetchReagents();
    }, [fetchReagents]);

    // Filter reagents
    const filteredReagents = useMemo(() => reagents.filter(r => {
        const matchesSearch = searchQuery === '' ||
            r.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
            r.manufacturer?.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesCategory = categoryFilter === '' || r.category === categoryFilter;
        return matchesSearch && matchesCategory;
    }), [reagents, searchQuery, categoryFilter]);

    // Group by category (including custom categories from reagents)
    const groupedReagents = useMemo(() => {
        const allCategories = new Set([
            ...CATEGORIES.map(c => c.value),
            ...filteredReagents.map(r => r.category)
        ]);

        return Array.from(allCategories).map(categoryValue => {
            const items = filteredReagents.filter(r => r.category === categoryValue);
            const predefined = CATEGORIES.find(c => c.value === categoryValue);
            return {
                category: { value: categoryValue, label: predefined?.label || categoryValue },
                items
            };
        }).filter(group => group.items.length > 0);
    }, [filteredReagents]);

    // -- Virtualizer for large catalogs (>VIRTUAL_THRESHOLD items) ------------
    const scrollParentRef = useRef<HTMLDivElement>(null);

    const flatItems = useMemo<FlatItem[]>(() => {
        if (filteredReagents.length <= VIRTUAL_THRESHOLD) return [];
        const items: FlatItem[] = [];
        for (const group of groupedReagents) {
            items.push({ type: 'header', group });
            for (const reagent of group.items) {
                items.push({ type: 'row', group, reagent });
            }
        }
        return items;
    }, [groupedReagents, filteredReagents.length]);

    const virtualizer = useVirtualizer({
        count: flatItems.length,
        getScrollElement: () => scrollParentRef.current,
        estimateSize: (i) => (flatItems[i]?.type === 'header' ? 44 : 48),
        overscan: 5,
    });


    const handleOpenAdd = () => {
        setEditingReagent(null);
        setIsModalOpen(true);
        setError(null);
    };

    const handleOpenDetail = (reagent: Reagent) => {
        setDetailReagent(reagent);
    };

    const handleOpenEdit = (reagent: Reagent) => {
        setEditingReagent(reagent);
        setIsModalOpen(true);
        setError(null);
    };

    const handleDelete = async (id: string) => {
        try {
            const result = await deleteReagent(id);
            if (result.success) {
                invalidateReagents();
                fetchReagents();
                setDeleteConfirm(null);
            } else {
                setError(result.error || '������ ��������');
            }
        } catch (_e) {
            setError('������ ����');
        }
    };

    const handleSave = async (data: Partial<Reagent>) => {
        try {
            const payload = {
                name: (data.name || '').trim(),
                category: (data.category || '').trim(),
                manufacturer: data.manufacturer || null,
                country: data.country || null,
                description: data.description || null,
                activeSubstance: data.activeSubstance || null,
                form: data.form || null,
            };

            if (!payload.name || !payload.category) {
                setError('�������� � ��������� �����������');
                return;
            }

            const result = editingReagent
                ? await updateReagent(editingReagent.id, payload)
                : await createReagent(payload);

            if (result.success) {
                invalidateReagents();
                await fetchReagents();
                setIsModalOpen(false);
                setError(null);
            } else {
                setError(result.error || '������ ����������');
            }
        } catch (_e) {
