/**
 * Hook encapsulating report export logic (PDF + Excel).
 *
 * Manages exporting state, builds report input, generates blobs,
 * and saves them via Tauri or browser fallback.
 */

import { useState, useMemo, useCallback } from 'react';
import type { ParseResult } from '@/lib/store/experiment-data-store';
import type { RheoCycle, GraceCycleResult } from '@/lib/analysis/types';
import type { RecipeComponent } from '@/lib/parsing/types';
import type { WaterParams } from '@/types';
import type { ChartSettings } from '@/lib/store/chart-settings-store';
import { generatePdfReportBlob, generateExcelReportBlob } from '@/lib/reports/client';
import { saveBlob } from '@/lib/reports/report-save';
import {
    mapRawData,
    mapCycleResults,
    buildPdfReportInput,
    buildExcelReportInput,
    type ReportBuildContext,
} from '@/lib/reports/report-builders';
import { extractExperimentMetadata } from '@/lib/metadata-utils';
import { logger as clientLogger } from '@/lib/client-logger';
import { debugLog } from '@/lib/utils/debug-logger';

export interface UseReportExportOptions {
    parseResult: ParseResult;
    editedRecipe: RecipeComponent[];
    editedWaterParams: Partial<WaterParams> | null;
    editedWaterSource: string;
    cycleResults: Map<number, GraceCycleResult>;
    cycles: RheoCycle[];
    // Settings
    language: 'ru' | 'en';
    unitSystem: 'SI' | 'Imperial';
    showTouchPoints: boolean;
    viscosityThreshold: number;
    showTargetTime: boolean;
    targetTime: number;
    showCalibration: boolean;
    showRawData: boolean;
    reportViscosityRates: number[];
    isExpert: boolean;
    companyName: string;
    companyLogo: string | null;
    reportSettings: ChartSettings;
}

export function useReportExport(options: UseReportExportOptions) {
    const [isExporting, setIsExporting] = useState(false);
    const [isExcelExporting, setIsExcelExporting] = useState(false);
    const [isCapturing, setIsCapturing] = useState(false);
    const [exportError, setExportError] = useState<string | null>(null);

    const { parseResult, cycleResults } = options;

    // Pre-compute data mappings once when source data changes
    const rawDataMapped = useMemo(() => mapRawData(parseResult.data), [parseResult.data]);
    const cycleResultsMapped = useMemo(() => mapCycleResults(cycleResults), [cycleResults]);

    const legacyFields = useMemo(
        () => extractExperimentMetadata(parseResult.metadata),
        [parseResult.metadata],
    );

    /** Build the shared context object for report builders. */
    const buildContext = useCallback((): ReportBuildContext => ({
        rawDataMapped,
        cycleResultsMapped,
        metadata: parseResult.metadata,
        legacyFields,
        editedRecipe: options.editedRecipe,
        editedWaterParams: options.editedWaterParams,
        editedWaterSource: options.editedWaterSource,
        cycles: options.cycles,
        companyName: options.companyName,
        companyLogo: options.companyLogo,
        reportSettings: options.reportSettings,
        language: options.language,
        unitSystem: options.unitSystem,
        showTouchPoints: options.showTouchPoints,
        viscosityThreshold: options.viscosityThreshold,
        showTargetTime: options.showTargetTime,
        targetTime: options.targetTime,
        showCalibration: options.showCalibration,
        showRawData: options.showRawData,
        reportViscosityRates: options.reportViscosityRates,
        isExpert: options.isExpert,
    }), [
        rawDataMapped, cycleResultsMapped, parseResult.metadata, legacyFields,
        options.editedRecipe, options.editedWaterParams, options.editedWaterSource,
        options.cycles, options.companyName, options.companyLogo, options.reportSettings,
        options.language, options.unitSystem, options.showTouchPoints,
        options.viscosityThreshold, options.showTargetTime, options.targetTime,
        options.showCalibration, options.showRawData, options.reportViscosityRates,
        options.isExpert,
    ]);

    const handleDownload = useCallback(async () => {
        setIsExporting(true);
        setIsCapturing(true);
        await new Promise(resolve => setTimeout(resolve, 100));
        setExportError(null);

        const timings: string[] = [];
        const t0 = performance.now();

        try {
            debugLog('ReportsPanel', 'Starting PDF generation...');
            console.time('[ReportsPanel] Total PDF time');
            console.time('[ReportsPanel] Capture SVG');
            clientLogger.info('[ReportsPanel] Capturing chart as SVG...');
            const _chartImage = null;
            console.timeEnd('[ReportsPanel] Capture SVG');

            const t2 = performance.now();
            timings.push(`Capture: ${(t2 - t0).toFixed(0)}ms`);

            const pdfInput = buildPdfReportInput(buildContext());
            const blob = await generatePdfReportBlob(pdfInput);

            const t3 = performance.now();
            timings.push(`PDF Gen: ${(t3 - t2).toFixed(0)}ms`);
            timings.push(`TOTAL: ${(t3 - t0).toFixed(0)}ms`);
            clientLogger.info('[ReportsPanel] PDF generation timings:', timings.join(', '));

            const filename = `${parseResult.metadata.filename || 'report'}_${new Date().toISOString().split('T')[0]}.pdf`;
            await saveBlob({
                blob,
                filename,
                filters: [{ name: 'PDF Document', extensions: ['pdf'] }],
            });
        } catch (err) {
            clientLogger.error('Report generation failed:', err);
            const errorMessage = err instanceof Error ? err.message : String(err);
            setExportError(`Ошибка генерации PDF: ${errorMessage}`);
        } finally {
            setIsCapturing(false);
            setIsExporting(false);
        }
    }, [buildContext, parseResult.metadata.filename]);

    const handleExcelDownload = useCallback(async () => {
        setIsExcelExporting(true);
        setExportError(null);
        try {
            const excelInput = buildExcelReportInput(buildContext());
            clientLogger.info('[ReportsPanel] Generating Excel with settings:', excelInput.settings);

            const blob = await generateExcelReportBlob(excelInput);
            const filename = `${parseResult.metadata.filename || 'report'}_${new Date().toISOString().split('T')[0]}.xlsx`;
            await saveBlob({
                blob,
                filename,
                filters: [{ name: 'Excel Spreadsheet', extensions: ['xlsx'] }],
            });
        } catch (err) {
            clientLogger.error('[ReportsPanel] Excel generation failed:', err);
            const errorMessage = err instanceof Error ? err.message : String(err);
            setExportError(`Ошибка генерации Excel: ${errorMessage}`);
        } finally {
            setIsExcelExporting(false);
        }
    }, [buildContext, parseResult.metadata.filename]);

    return {
        isExporting,
        isExcelExporting,
        isCapturing,
        exportError,
        clearError: useCallback(() => setExportError(null), []),
        handleDownload,
        handleExcelDownload,
        /** Pre-mapped raw data — reuse for chart preview */
        chartData: rawDataMapped,
    };
}

import { logger as clientLogger } from '@/lib/client-logger';

import { useState } from 'react';
import { readFile, writeFile } from '@tauri-apps/plugin-fs';
import { invoke } from '@tauri-apps/api/core';
import { open, save } from '@tauri-apps/plugin-dialog';
import {
    FileUp, FileDown, Check, AlertTriangle, Loader2,
    Database, Beaker
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { format } from 'date-fns';
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { getExperimentsCount } from '@/lib/experiments/client';
import { exportReagents, importReagents } from '@/lib/reagents/client';

interface ExportStats {
    total: number;
    exported: number;
    filename: string;
}

interface ImportResult {
    imported: number;
    updated?: number;
    skipped: number;
    errors: string[];
}

export function ExperimentExportImport() {
    const [activeTab, setActiveTab] = useState('experiments');
    const [isExporting, setIsExporting] = useState(false);
    const [isImporting, setIsImporting] = useState(false);
    const [exportStats, setExportStats] = useState<ExportStats | null>(null);
    const [importResult, setImportResult] = useState<ImportResult | null>(null);
    const [error, setError] = useState<string | null>(null);

    // ── Export: Experiments (as .db file via save dialog) ──────────────────
    const handleExportExperiments = async () => {
        setIsExporting(true);
        setError(null);
        setExportStats(null);

        try {
            const timestamp = format(new Date(), 'yyyy-MM-dd_HH-mm');
            const defaultName = `rheolab_export_${timestamp}.db`;

            const filePath = await save({
                defaultPath: defaultName,
                filters: [
                    { name: 'База данных RheoLab', extensions: ['db'] },
                ],
            });
            if (!filePath) return; // User cancelled

            const result = await invoke<{
                success: boolean;
                error?: string;
                name?: string;
            }>('backup_export_db', { targetPath: filePath });

            if (!result.success) {
                throw new Error(result.error || 'Ошибка экспорта');
            }

            const count = await getExperimentsCount();
            const filename = filePath.split(/[\\/]/).pop() || defaultName;
            setExportStats({ total: count, exported: count, filename });
        } catch (e) {
            setError(e instanceof Error ? e.message : 'Ошибка экспорта');
        } finally {
            setIsExporting(false);
        }
    };

    // ── Export: Reagents (as .json file via save dialog) ───────────────────
    const handleExportReagents = async () => {
        setIsExporting(true);
        setError(null);
        setExportStats(null);

        try {
            const data = await exportReagents();
            if (!data.success) throw new Error(data.error || 'Ошибка экспорта');

            const timestamp = format(new Date(), 'yyyy-MM-dd_HH-mm');
            const defaultName = `rheolab_reagents_${timestamp}.json`;

            const filePath = await save({
                defaultPath: defaultName,
                filters: [
                    { name: 'JSON', extensions: ['json'] },
                ],
            });
            if (!filePath) return; // User cancelled

            const json = JSON.stringify(data, null, 2);
            await writeFile(filePath, new TextEncoder().encode(json));

            const filename = filePath.split(/[\\/]/).pop() || defaultName;
            setExportStats({
                total: data.total,
                exported: data.reagents.length,
                filename,
            });
        } catch (e) {
            setError(e instanceof Error ? e.message : 'Ошибка экспорта');
        } finally {
            setIsExporting(false);
        }
    };

    // ── Handle export button click ────────────────────────────────────────
    const handleExport = async () => {
        if (activeTab === 'experiments') {
            await handleExportExperiments();
        } else {
            await handleExportReagents();
        }
    };

    // ── Import: native file dialog (.db or .json) ─────────────────────────
    const handleNativeImport = async () => {
        try {
            const isExperiments = activeTab === 'experiments';

            const filePath = await open({
                multiple: false,
                filters: isExperiments
                    ? [
                        { name: 'База данных RheoLab', extensions: ['db'] },
                        { name: 'JSON (устар.)', extensions: ['json'] },
                    ]
                    : [
                        { name: 'JSON', extensions: ['json'] },
                    ],
            });
            if (!filePath) return;

            const path = typeof filePath === 'string' ? filePath : filePath;

            if (path.endsWith('.db')) {
                // SQLite DB merge import
                setIsImporting(true);
                setError(null);
                setImportResult(null);

                const result = await invoke<{
                    success: boolean;
                    error?: string;
                    imported: number;
                    skipped: number;
                }>('backup_import_db', { filePath: path });

                if (!result.success) {
                    setError(result.error || 'Ошибка импорта базы данных');
                } else {
                    setImportResult({
                        imported: result.imported,
                        skipped: result.skipped,
                        errors: [],
                    });
                }
            } else {
                // JSON file import (reagents or legacy experiments)
                setIsImporting(true);
                setError(null);
                setImportResult(null);

                const bytes = await readFile(path);
                const text = new TextDecoder().decode(bytes);
                let jsonData;

                try {
                    jsonData = JSON.parse(text);
                } catch (_e) {
                    throw new Error('Невалидный JSON файл');
                }

                if (jsonData.reagents || (Array.isArray(jsonData) && jsonData[0]?.category)) {
                    const reagentsPayload = (jsonData.reagents || jsonData) as unknown[];
                    const result = await importReagents(reagentsPayload);
                    if (!result.success) throw new Error(result.error || 'Ошибка импорта');
                    setImportResult({
                        imported: result.imported,
                        updated: result.updated,
                        skipped: result.skipped,
                        errors: result.errors || [],
                    });
                } else {
                    throw new Error('Не удалось определить тип данных в файле. Используйте формат .db для экспериментов.');
                }
            }
        } catch (e) {
            setError(e instanceof Error ? e.message : 'Ошибка импорта');
        } finally {
            setIsImporting(false);
        }
    };

    return (
        <div className="space-y-6">
            <Tabs defaultValue="experiments" onValueChange={setActiveTab} className="w-full">
                <TabsList className="grid w-full grid-cols-2 bg-slate-800/50">
                    <TabsTrigger value="experiments" className="gap-2">
                        <Database className="w-4 h-4" />
                        Эксперименты
                    </TabsTrigger>
                    <TabsTrigger value="reagents" className="gap-2">
                        <Beaker className="w-4 h-4" />
                        База реагентов
                    </TabsTrigger>
                </TabsList>

                {/* Experiments Tab Content */}
                <TabsContent value="experiments" className="space-y-4 pt-4">
                    <div>
                        <h3 className="text-sm font-medium text-slate-200">Экспорт и импорт экспериментов</h3>
                        <p className="text-xs text-slate-500">Перенос базы данных между филиалами в формате SQLite (.db)</p>
                    </div>
                    <div className="p-4 bg-blue-500/5 border border-blue-500/10 rounded-lg">
                        <p className="text-xs text-blue-200/70 leading-relaxed">
                            <Database className="w-3 h-3 inline mr-1 mb-0.5" />
                            Экспорт создаёт полную копию базы данных. При импорте новые эксперименты добавляются
                            в текущую базу, дубликаты пропускаются. Существующие данные не затрагиваются.
                        </p>
                    </div>
                </TabsContent>

                {/* Reagents Tab Content */}
                <TabsContent value="reagents" className="space-y-4 pt-4">
                    <div>
                        <h3 className="text-sm font-medium text-slate-200">Справочник реагентов</h3>
                        <p className="text-xs text-slate-500">Экспорт и обновление глобального каталога химии</p>
                    </div>
                    <div className="p-4 bg-amber-500/5 border border-amber-500/10 rounded-lg">
                        <p className="text-xs text-amber-200/70 leading-relaxed">
                            <AlertTriangle className="w-3 h-3 inline mr-1 mb-0.5" />
                            При импорте реагентов, если реагент с таким именем уже существует, его данные будут
                            обновлены (категория, производитель и т.д.). Это полезно для синхронизации справочников.
                        </p>
                    </div>
                </TabsContent>
            </Tabs>

            {/* Common Action Buttons */}
            <div className="flex gap-3">
                <Button
                    onClick={handleExport}
                    disabled={isExporting || isImporting}
                    variant="outline"
                    className="gap-2 flex-1"
                >
                    {isExporting ? <Loader2 className="w-4 h-4 animate-spin" /> : <FileDown className="w-4 h-4" />}
                    {activeTab === 'experiments' ? 'Экспорт базы данных' : 'Экспорт каталога'}
                </Button>

                <Button
                    onClick={handleNativeImport}
                    disabled={isExporting || isImporting}
                    variant="outline"
                    className="gap-2 flex-1"
                >
                    {isImporting ? <Loader2 className="w-4 h-4 animate-spin" /> : <FileUp className="w-4 h-4" />}
                    Импорт из файла
                </Button>
            </div>

            {/* Status Messages */}
            {error && (
                <div className="p-3 bg-red-500/10 border border-red-500/20 rounded text-red-400 text-sm flex items-center gap-2">
                    <AlertTriangle className="w-4 h-4 shrink-0" />
                    {error}
                </div>
            )}

            {exportStats && (
                <div className="p-3 bg-green-500/10 border border-green-500/20 rounded text-green-400 text-sm flex items-center gap-2">
                    <Check className="w-4 h-4 shrink-0" />
                    <div>
                        <div>Экспортировано {exportStats.exported} записей</div>
                        <div className="text-xs opacity-70">Файл: {exportStats.filename}</div>
                    </div>
                </div>
            )}

            {importResult && (
                <div className={`p-3 border rounded text-sm ${importResult.errors.length > 0
                    ? 'bg-yellow-500/10 border-yellow-500/20 text-yellow-400'
                    : 'bg-green-500/10 border-green-500/20 text-green-400'
                    }`}>
                    <div className="flex items-center gap-2">
                        <Check className="w-4 h-4 shrink-0" />
                        <div>
                            <div>
                                {importResult.imported > 0 && `Добавлено: ${importResult.imported}. `}
                                {importResult.updated !== undefined && importResult.updated > 0 && `Обновлено: ${importResult.updated}. `}
                                {importResult.skipped > 0 && `Пропущено (дубликаты): ${importResult.skipped}.`}
                            </div>
                            {importResult.errors.length > 0 && (
                                <div className="text-xs mt-1 opacity-70">
                                    Ошибки: {importResult.errors.slice(0, 3).join(', ')}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import { logger as clientLogger } from '@/lib/client-logger';

import { useState, useEffect, useRef } from 'react';
import { ChevronDown, X, Beaker } from 'lucide-react';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { useCatalogStore } from '@/lib/store/catalog-store';

interface Reagent {
    id: string;
    name: string;
    category: string;
    manufacturer?: string | null;
    country?: string | null;
}

interface ReagentAutocompleteProps {
    value: string;
    onChange: (value: string) => void;
    placeholder?: string;
}

// Group reagents by category
function groupByCategory(reagents: Reagent[]): Map<string, Reagent[]> {
    const groups = new Map<string, Reagent[]>();
    for (const r of reagents) {
        if (!groups.has(r.category)) {
            groups.set(r.category, []);
        }
        groups.get(r.category)!.push(r);
    }
    return groups;
}

// Category display names
const categoryLabels: Record<string, string> = {
    'Gelling Agent': 'Гелеобразователи',
    'Crosslinker': 'Сшиватели',
    'Breaker': 'Деструкторы',
    'Buffer': 'pH-буферы',
    'Stabilizer': 'Стабилизаторы',
    'Clay Control': 'Контроль глин',
    'Friction Reducer': 'Понизители трения',
    'Biocide': 'Бактерициды',
    'Scale Inhibitor': 'Ингибиторы отложений',
    'Surfactant': 'ПАВ',
    'Viscosifier': 'Загустители',
};

export function ReagentAutocomplete({ value, onChange, placeholder = 'Выберите реагент...' }: ReagentAutocompleteProps) {
    const [isOpen, setIsOpen] = useState(false);
    const [search, setSearch] = useState('');
    const reagents = useCatalogStore(s => s.reagents);
    const isLoading = useCatalogStore(s => s.reagentsLoading);
    const fetchReagents = useCatalogStore(s => s.fetchReagents);
    const containerRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);

    // Fetch reagents on mount (shared store deduplicates)
    useEffect(() => {
        fetchReagents();
    }, [fetchReagents]);

    // Close dropdown when clicking outside
    useEffect(() => {
        function handleClickOutside(e: MouseEvent) {
            if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
                setIsOpen(false);
            }
        }
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    // Filter reagents by search query
    const filteredReagents = reagents.filter(r =>
        r.name.toLowerCase().includes(search.toLowerCase()) ||
        r.category.toLowerCase().includes(search.toLowerCase()) ||
        (r.manufacturer?.toLowerCase().includes(search.toLowerCase())) ||
        (r.country?.toLowerCase().includes(search.toLowerCase()))
    );

    const groupedReagents = groupByCategory(filteredReagents);

    const handleSelect = (reagentName: string) => {
        onChange(reagentName);
        setSearch('');
        setIsOpen(false);
    };

    const handleClear = () => {
        onChange('');
        setSearch('');
    };

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setSearch(e.target.value);
        onChange(e.target.value); // Also filter as user types
        if (!isOpen) setIsOpen(true);
    };

    return (
        <div ref={containerRef} className="relative">
            {/* Input Field */}
            <div className="relative">
                <Input
                    ref={inputRef}
                    type="text"
                    value={search || value}
                    onChange={handleInputChange}
                    onFocus={() => setIsOpen(true)}
                    className="bg-slate-900 border-purple-500/30 text-white pl-8 pr-16 focus-visible:ring-purple-500"
                    placeholder={placeholder}
                />
                <Beaker className="w-4 h-4 text-purple-400 absolute left-2.5 top-2.5" />
                <div className="absolute right-1 top-0.5 flex items-center gap-0.5 h-full">
                    {value && (
                        <Button
                            variant="ghost"
                            size="icon"
                            onClick={handleClear}
                            aria-label="Очистить"
                            className="h-7 w-7 text-slate-400 hover:text-white"
                        >
                            <X className="w-3 h-3" />
                        </Button>
                    )}
                    <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => setIsOpen(!isOpen)}
                        aria-label={isOpen ? 'Свернуть список' : 'Открыть список'}
                        aria-expanded={isOpen}
                        className="h-7 w-7 text-slate-400 hover:text-white"
                    >
                        <ChevronDown className={`w-4 h-4 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
                    </Button>
                </div>
            </div>

            {/* Dropdown */}
            {isOpen && (
                <div className="absolute z-50 w-full mt-1 bg-slate-900 border border-slate-700 rounded-lg shadow-xl max-h-80 overflow-y-auto">
                    {isLoading ? (
                        <div className="p-4 text-center text-slate-500 text-sm">
                            Загрузка...
                        </div>
                    ) : filteredReagents.length === 0 ? (
                        <div className="p-4 text-center text-slate-500 text-sm">
                            {search ? `Ничего не найдено по "${search}"` : 'Нет реагентов в каталоге'}
                        </div>
                    ) : (
                        <div className="py-1">
                            {Array.from(groupedReagents.entries()).map(([category, items]) => (
                                <div key={category}>
                                    {/* Category Header */}
                                    <div className="px-3 py-1.5 text-xs font-semibold text-purple-400 bg-slate-800/50 sticky top-0">
                                        {categoryLabels[category] || category}
                                    </div>
                                    {/* Reagent Items */}
                                    {items.map(reagent => (
                                        <button
                                            key={reagent.id}
                                            onClick={() => handleSelect(reagent.name)}
                                            className={`w-full text-left px-4 py-2 text-sm hover:bg-slate-800 transition-colors ${value === reagent.name ? 'bg-purple-500/20 text-purple-300' : 'text-slate-300'
                                                }`}
                                        >
                                            <span className="font-medium">{reagent.name}</span>
                                            {reagent.country && (
                                                <span className="ml-2 text-xs text-slate-500">({reagent.country})</span>
                                            )}
                                        </button>
                                    ))}
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

/**
 * useRheologyChartOptions
 *
 * Builds the uPlot.Options object for the RheologyChart component.
 * Extracted so the main component stays readable and the axes/series
 * configuration is isolated and independently testable.
 */
import { useMemo } from 'react';
import uPlot from 'uplot';
import { tooltipPlugin } from '@/components/charts/plugins/tooltip';
import { zoomPlugin } from '@/components/charts/plugins/zoom';
import { touchPointsPlugin } from '@/components/charts/plugins/touchPoints';
import { getStrokeDasharray } from '@/lib/store/chart-settings-store';
import type { ChartSettings } from '@/lib/store/chart-settings-store';
import type { TouchPointMarker } from './useRheologyData';

// Show per-series dots only when zoomed in enough (< 60 visible data points).
const showPointsWhenZoomed: uPlot.Series['points'] = {
    show: (_u: uPlot, _si: number, idx0: number, idx1: number) => (idx1 - idx0) < 60,
};

interface UseRheologyChartOptionsParams {
    activeSettings: ChartSettings;
    chartSettings: ChartSettings;
    showTemperature: boolean;
    showShearRate: boolean;
    showPressure: boolean;
    showRpm: boolean;
    showBathTemperature: boolean;
    pdfMode: boolean;
    captureMode: boolean;
    touchPoints: TouchPointMarker[];
    effectiveShearRateAxis: 'left' | 'right';
    effectivePressureAxis: 'left' | 'right';
    axisMode: 'shared' | 'individual';
    viscosityThreshold: number;
    showTouchPoints: boolean;
    targetTime: number;
}

export function useRheologyChartOptions({
    activeSettings,
    chartSettings,
    showTemperature,
    showShearRate,
    showPressure,
    showRpm,
    showBathTemperature,
    pdfMode,
    captureMode,
    touchPoints,
    effectiveShearRateAxis,
    effectivePressureAxis,
    axisMode,
    viscosityThreshold,
    showTouchPoints,
    targetTime,
}: UseRheologyChartOptionsParams): uPlot.Options {
    // eslint-disable-next-line react-hooks/exhaustive-deps -- previewMode/showTouchPoints/targetTime/viscosityThreshold are chart render props, not data deps
    return useMemo<uPlot.Options>(() => {
        const isDark = !pdfMode && !captureMode;
        const textColor = isDark ? '#94a3b8' : '#334155';
        const gridColor = isDark ? '#334155' : '#e2e8f0';
        const axisColor = isDark ? '#475569' : '#cbd5e1';
        // Apply gridOpacity to grid stroke color
        const gridColorOpa = (() => {
            const op = activeSettings.gridOpacity ?? 1;
            if (op >= 1) return gridColor;
            const hex = gridColor.replace('#', '');
            return `rgba(${parseInt(hex.slice(0,2),16)},${parseInt(hex.slice(2,4),16)},${parseInt(hex.slice(4,6),16)},${op})`;
        })();

        // Helper to convert dasharray string to array of numbers
        const parseDash = (dashStr?: string) => {
            if (!dashStr) return [];
            return dashStr.split(' ').map(Number);
        };

        const isShared = axisMode === 'shared';
        // Compute per-metric uPlot scale names
        const sViscosity   = isShared ? 'left' : 'viscosity';
        const sTemperature = isShared ? 'right' : 'temperature';
        const sShearRate   = isShared ? (effectiveShearRateAxis === 'right' ? 'right' : 'left') : 'shearRate';
        const sPressure    = isShared ? (effectivePressureAxis   === 'right' ? 'right' : 'left') : 'pressure';
        const sRpm         = isShared ? (activeSettings.lines.rpm.axis === 'right' ? 'right' : 'left') : 'rpm';
        // Bath temperature shares the same Y scale as sample temperature (same °C units)
        const sBathTemperature = sTemperature;

        return {
            width: 100, // Initial dummy size, will be overridden by UPlotChart props
            height: 100,
            // Cap device pixel ratio at 1.5 — avoids 4× GPU texture scaling on HiDPI
            // displays (DPR=2 → 2560×1400 backing store) while keeping text crisp.
            pxRatio: Math.min(window.devicePixelRatio || 1, 1.5),
            padding: [10, 20, 10, 10], // [top, right, bottom, left]
            legend: { show: false },
            cursor: {
                points: {
                    size: 8,
                    width: 2,
                    // Use each series' own colour for cursor dot (per-series color)
                    fill: (u: uPlot, si: number) => {
                        const s = u.series[si]?.stroke;
                        return typeof s === 'string' ? s : (isDark ? '#1e293b' : '#fff');
                    },
                    stroke: (u: uPlot, si: number) => {
                        const s = u.series[si]?.stroke;
                        return typeof s === 'string' ? s : (isDark ? '#fff' : '#000');
                    },
                }
            },
            plugins: [
                ...(!captureMode && !pdfMode && chartSettings.tooltipEnabled !== false ? [tooltipPlugin({
                    formatter: (idx: number, val: number) => {
                        const units = ['', 'сП', '°C', '1/с', 'бар', 'об/мин', '°C'];
                        return `${val} ${units[idx]}`;
                    },
                    titleFormatter: (val: number) => `Время: ${val} мин`,
                })] : []),
                zoomPlugin(),
                touchPointsPlugin({
                    touchPoints,
                    viscosityThreshold,
                    showTouchPoints,
                    targetTime,
                    pdfMode,
                    captureMode,
                    scaleName: sViscosity,
                }),
            ],
            scales: {
                x: { time: false },
                ...(isShared ? {
                    left:  { auto: true },
                    right: { auto: true },
                } : {
                    viscosity:   { auto: true },
                    temperature: { auto: true },
                    shearRate:   { auto: true },
                    pressure:    { auto: true },
                    rpm:         { auto: true },
                }),
            },
            axes: (() => {
                const xAxis: uPlot.Axis = {
                    scale: 'x',
                    label: 'Время (мин)',
                    labelSize: 20,
                    labelFont: '12px sans-serif',
                    font: '12px sans-serif',
                    stroke: textColor,
                    grid: { show: activeSettings.showGridLines !== false, stroke: gridColorOpa, width: 1, dash: [3, 3] },
                    ticks: { stroke: axisColor, width: 1 },
                };
                if (isShared) {
                    const leftLabels = ['Вязкость (сП)'];
                    if (showShearRate && effectiveShearRateAxis !== 'right') leftLabels.push('Скор. сдвига (1/с)');
                    if (showPressure && effectivePressureAxis !== 'right')   leftLabels.push('Давление (бар)');
                    if (showRpm     && activeSettings.lines.rpm.axis !== 'right') leftLabels.push('Обороты (об/мин)');
                    const rightLabels: string[] = [];
                    if (showTemperature) rightLabels.push('Температура (°C)');
                    if (showShearRate && effectiveShearRateAxis === 'right') rightLabels.push('Скор. сдвига (1/с)');
                    if (showPressure && effectivePressureAxis   === 'right') rightLabels.push('Давление (бар)');
                    if (showRpm     && activeSettings.lines.rpm.axis === 'right') rightLabels.push('Обороты (об/мин)');
                    return [
                        xAxis,
                        {
                            scale: 'left',
                            label: leftLabels.join(' / '),
                            labelSize: 20,
                            labelFont: '11px sans-serif',
                            font: '12px sans-serif',
                            // Pin gutter width so shared-axes charts always have consistent
                            // horizontal margins regardless of tick-label auto-sizing.
                            size: 70,
                            stroke: activeSettings.lines.viscosity.color,
                            grid: { show: activeSettings.showGridLines !== false, stroke: gridColorOpa, width: 1, dash: [3, 3] },
                            ticks: { stroke: activeSettings.lines.viscosity.color, width: 1 },
                        },
                        {
                            scale: 'right',
                            side: 1,
                            show: rightLabels.length > 0,
                            label: rightLabels.join(' / '),
                            labelSize: 20,
                            labelFont: '11px sans-serif',
                            font: '12px sans-serif',
                            size: 65,
                            stroke: activeSettings.lines.temperature.color,
                            grid: { show: false },
                            ticks: { stroke: activeSettings.lines.temperature.color, width: 1 },
                        },
                    ];
                }
                return [
                    xAxis,
                    {
                        scale: 'viscosity',
                        label: 'Вязкость (сП)',
                        labelSize: 20,
                        labelFont: '11px sans-serif',
                        font: '12px sans-serif',
                        // Pin size so the left-side gutter width is stable — matches
                        // shared-mode left axis size (70px).
                        size: 70,
                        stroke: activeSettings.lines.viscosity.color,
                        grid: { show: activeSettings.showGridLines !== false, stroke: gridColorOpa, width: 1, dash: [3, 3] },
                        ticks: { stroke: activeSettings.lines.viscosity.color, width: 1 },
                    },
                    {
                        scale: 'temperature',
                        side: 1,
                        // Bath temperature shares the temperature scale — show the axis
                        // whenever either metric is visible (not just when temperature itself is on).
                        show: showTemperature || showBathTemperature,
                        label: showTemperature && showBathTemperature
                            ? 'Температура / Темп. бани (°C)'
                            : showBathTemperature
                                ? 'Темп. бани (°C)'
                                : 'Температура (°C)',
                        labelSize: 20,
                        labelFont: '11px sans-serif',
                        font: '12px sans-serif',
                        // Pin size so the right-side gutter width is stable regardless
                        // of label length — matches shared-mode right axis size.
                        size: 65,
                        stroke: activeSettings.lines.temperature.color,
                        grid: { show: false },
                        ticks: { stroke: activeSettings.lines.temperature.color, width: 1 },
                    },
                    {
                        scale: 'shearRate',
                        side: effectiveShearRateAxis === 'right' ? 1 : 3,
                        show: showShearRate,
                        label: 'Скор. сдвига (1/с)',
                        labelSize: 20,
                        labelFont: '11px sans-serif',
                        font: '12px sans-serif',
                        size: 65,
                        stroke: activeSettings.lines.shearRate.color,
                        grid: { show: false },
                        ticks: { stroke: activeSettings.lines.shearRate.color, width: 1 },
                    },
                    {
                        scale: 'pressure',
                        side: effectivePressureAxis === 'right' ? 1 : 3,
                        show: showPressure,
                        label: 'Давление (бар)',
                        labelSize: 20,
                        labelFont: '11px sans-serif',
                        font: '12px sans-serif',
                        size: 65,
                        stroke: activeSettings.lines.pressure.color,
                        grid: { show: false },
                        ticks: { stroke: activeSettings.lines.pressure.color, width: 1 },
                    },
                    {
                        scale: 'rpm',
                        side: 3,
                        show: showRpm,
                        label: 'Обороты (об/мин)',
                        labelSize: 20,
                        labelFont: '11px sans-serif',
                        font: '12px sans-serif',
                        size: 65,
                        stroke: activeSettings.lines.rpm.color,
                        grid: { show: false },
                        ticks: { stroke: activeSettings.lines.rpm.color, width: 1 },
                    },
                    // Bath temperature shares the temperature scale — no separate axis needed
                ];
            })(),
            series: [
                { label: 'Время' }, // X-axis
                {
                    label: 'Вязкость',
                    scale: sViscosity,
                    stroke: activeSettings.lines.viscosity.color,
                    width: activeSettings.lines.viscosity.width,
                    dash: parseDash(getStrokeDasharray(activeSettings.lines.viscosity.style)),
                    show: true,
                    points: showPointsWhenZoomed,
                },
                {
                    label: 'Температура',
                    scale: sTemperature,
                    stroke: activeSettings.lines.temperature.color,
                    width: activeSettings.lines.temperature.width,
                    dash: parseDash(getStrokeDasharray(activeSettings.lines.temperature.style)),
                    show: showTemperature,
                    points: showPointsWhenZoomed,
                },
                {
                    label: 'Скор. сдвига',
                    scale: sShearRate,
                    stroke: activeSettings.lines.shearRate.color,
                    width: activeSettings.lines.shearRate.width,
                    dash: parseDash(getStrokeDasharray(activeSettings.lines.shearRate.style)),
                    show: showShearRate,
                    points: showPointsWhenZoomed,
                },
                {
                    label: 'Давление',
                    scale: sPressure,
                    stroke: activeSettings.lines.pressure.color,
                    width: activeSettings.lines.pressure.width,
                    dash: parseDash(getStrokeDasharray(activeSettings.lines.pressure.style)),
                    show: showPressure,
                    points: showPointsWhenZoomed,
                },
                {
                    label: 'Обороты',
                    scale: sRpm,
                    stroke: activeSettings.lines.rpm.color,
                    width: activeSettings.lines.rpm.width,
                    dash: parseDash(getStrokeDasharray(activeSettings.lines.rpm.style)),
                    show: showRpm,
                    points: showPointsWhenZoomed,
                },
                {
                    label: 'Темп. бани',
                    scale: sBathTemperature,
                    stroke: activeSettings.lines.bathTemperature?.color ?? '#fb923c',
                    width: activeSettings.lines.bathTemperature?.width ?? 2,
                    dash: parseDash(getStrokeDasharray(activeSettings.lines.bathTemperature?.style ?? 'dashed')),
                    show: showBathTemperature,
                    points: showPointsWhenZoomed,
                },
            ],
        };
    }, [activeSettings, showTemperature, showShearRate, showPressure, showRpm, showBathTemperature, pdfMode, captureMode, touchPoints, effectiveShearRateAxis, effectivePressureAxis, axisMode]);
}

import { AIProvider } from './models';

// Lazy-load the openai module so it is NOT bundled in the main chunk.
// openai (~1 MB) is only needed when the user triggers AI parsing.
let _openaiMod: typeof import('openai') | null = null;
async function loadOpenAI(): Promise<typeof import('openai')> {
    if (!_openaiMod) {
        _openaiMod = await import('openai');
    }
    return _openaiMod;
}

const GROQ_BASE_URL = (typeof import.meta !== 'undefined' ? import.meta.env?.VITE_GROQ_BASE_URL : undefined) || 'https://api.groq.com/openai/v1';
const DEFAULT_AI_MODEL = 'meta-llama/llama-4-scout-17b-16e-instruct';

const GROQ_FALLBACK_MODELS = [
    'meta-llama/llama-4-scout-17b-16e-instruct',
    'llama-3.3-70b-versatile'
];

export interface AICompletionResult {
    content: string | null;
    model: string;
    usage?: {
        prompt_tokens: number;
        completion_tokens: number;
        total_tokens: number;
    };
    keyIndex?: number;
    keyMask?: string;
}

export type AIErrorCode =
    | 'AUTH_ERROR'
    | 'RATE_LIMIT'
    | 'SERVER_ERROR'
    | 'NETWORK_ERROR'
    | 'NO_API_KEYS'
    | 'UNKNOWN_ERROR';

export class AIError extends Error {
    code: AIErrorCode;
    provider: AIProvider;

    constructor(message: string, code: AIErrorCode, provider: AIProvider) {
        super(message);
        this.name = 'AIError';
        this.code = code;
        this.provider = provider;
    }
}

// Session statistics for token usage tracking
export const sessionTokenUsage = {
    requests: 0,
    promptTokens: 0,
    completionTokens: 0,
    totalTokens: 0,
    keysUsed: new Set<string>(),
};

// Helper to mask API key for logging (show first 8 + last 4 chars)
function maskApiKey(key: string): string {
    if (key.length <= 12) return '***';
    return `${key.slice(0, 8)}...${key.slice(-4)}`;
}

export function resetSessionStats() {
    sessionTokenUsage.requests = 0;
    sessionTokenUsage.promptTokens = 0;
    sessionTokenUsage.completionTokens = 0;
    sessionTokenUsage.totalTokens = 0;
    sessionTokenUsage.keysUsed.clear();
}

/**
 * Fetch API keys via the platform bridge (desktop-only)
 * Returns all keys for the provider, with active key first
 */
async function getKeysFromDB(provider: string = 'groq'): Promise<string[]> {
    try {
        const { getBridge } = await import('@/lib/tauri/bridge');
        const bridge = getBridge();

        // In Tauri mode, use aiKey() to get the actual decrypted key.
        // bridge.apiKeys.list() returns masked '********' keys which are useless.
        if (bridge.platform === 'tauri' && bridge.apiKeys?.aiKey) {
            const decryptedKey = await bridge.apiKeys.aiKey(provider);
            return decryptedKey ? [decryptedKey] : [];
        }

        // Web fallback — list may return masked keys
        const keys = await bridge.apiKeys.list();
        return keys
            .filter(k => k.provider === provider && k.key && k.key !== '********')
            .map(k => k.key);
    } catch (error) {
        console.error('[AI Client] Failed to fetch keys from bridge:', error);
        return [];
    }
}

/**
 * Generates an AI completion using Groq with key rotation and model fallback.
 * Keys are fetched from database only (user-saved keys).
 */
export async function getAICompletion(
    systemPrompt: string,
    userContent: string,
    model?: string,
    temperature: number = 0.2,
    timeout: number = 60000,
    apiKey?: string
): Promise<AICompletionResult> {
    const { default: OpenAI } = await loadOpenAI();

    // Get keys from database (with rotation support)
    let apiKeys: string[] = [];

    if (apiKey) {
        // If explicit key passed (from client), use it first
        apiKeys.push(apiKey);
    }

    // Fetch all keys from DB for rotation
    const dbKeys = await getKeysFromDB('groq');
    apiKeys.push(...dbKeys);

    // Deduplicate
    apiKeys = [...new Set(apiKeys)];

    if (apiKeys.length === 0) {
        throw new AIError(
            'API-ключи не настроены. Добавьте ключ Groq в Настройках.',
            'NO_API_KEYS',
            'groq'
        );
    }

    // Prepare models to try
    const modelsToTry: string[] = [];
    modelsToTry.push(model || DEFAULT_AI_MODEL);
    for (const fallback of GROQ_FALLBACK_MODELS) {
        if (!modelsToTry.includes(fallback)) {
            modelsToTry.push(fallback);
        }
    }

    let lastError: Error | null = null;

    for (const currentModel of modelsToTry) {
        for (let keyIndex = 0; keyIndex < apiKeys.length; keyIndex++) {
            const currentKey = apiKeys[keyIndex];
            const client = new OpenAI({
                apiKey: currentKey,
                baseURL: GROQ_BASE_URL,
                maxRetries: 1,
                timeout: timeout,
                dangerouslyAllowBrowser: true,
            });

            try {
                if (import.meta.env.DEV) console.log(`[AI Client] 📤 Sending request to Groq (${currentModel}) key ${keyIndex + 1}/${apiKeys.length} (${maskApiKey(currentKey)})...`);
                const completion = await client.chat.completions.create({
                    model: currentModel,
                    temperature: temperature,
                    messages: [
                        { role: 'system', content: systemPrompt },
                        { role: 'user', content: userContent },
                    ],
                });

                const usage = completion.usage;
                if (usage) {
                    sessionTokenUsage.requests++;
                    sessionTokenUsage.promptTokens += usage.prompt_tokens || 0;
                    sessionTokenUsage.completionTokens += usage.completion_tokens || 0;
                    sessionTokenUsage.totalTokens += usage.total_tokens || 0;
                    sessionTokenUsage.keysUsed.add(maskApiKey(currentKey));

                    if (import.meta.env.DEV) console.log(`[AI Client] ✅ Success!`);
                    if (import.meta.env.DEV) console.log(`[AI Client] 📊 Tokens: prompt=${usage.prompt_tokens}, completion=${usage.completion_tokens}, total=${usage.total_tokens}`);
                    if (import.meta.env.DEV) console.log(`[AI Client] 📈 Session: requests=${sessionTokenUsage.requests}, total_tokens=${sessionTokenUsage.totalTokens}, keys_used=${sessionTokenUsage.keysUsed.size}`);
                } else {
                    if (import.meta.env.DEV) console.log(`[AI Client] ✅ Success! Tokens: N/A`);
                }

                return {
                    content: completion.choices[0].message.content,
                    model: completion.model || currentModel,
                    usage: completion.usage,
                    keyIndex: keyIndex + 1,
                    keyMask: maskApiKey(currentKey)
                };
            } catch (error) {
                lastError = error as Error;
                const status = error instanceof OpenAI.APIError ? error.status : 'Unknown';
                console.error(`[AI Client] ❌ Failed (${status}): ${(error as Error)?.message?.slice(0, 100)}`);

                // Retry with next key if rate limited or auth error
                if (error instanceof OpenAI.APIError) {
                    if (status === 401 || status === 429 || status === 402) {
                        continue;
                    }
                }
                // Non-retryable error - try next model
                break;
            }
        }
    }

    // All attempts failed
    let code: AIErrorCode = 'UNKNOWN_ERROR';
    const message = lastError?.message || 'Неизвестная ошибка AI';

    if (lastError instanceof OpenAI.APIError) {
        const status = lastError.status;
        if (status === 401) code = 'AUTH_ERROR';
        else if (status === 429) code = 'RATE_LIMIT';
        else if (status && status >= 500) code = 'SERVER_ERROR';
    }

    throw new AIError(message, code, 'groq');
}

/**
 * Validates a Groq API Key by making a lightweight request
 */
export async function validateGroqKey(apiKey: string): Promise<{ isValid: boolean; error?: string }> {
    const { default: OpenAI } = await loadOpenAI();

    if (!apiKey) return { isValid: false, error: 'API-ключ пуст' };

    try {
        const client = new OpenAI({
            apiKey: apiKey,
            baseURL: GROQ_BASE_URL,
            maxRetries: 0,
            timeout: 10000,
        });

        await client.chat.completions.create({
            model: DEFAULT_AI_MODEL,
            messages: [{ role: 'user', content: 'ping' }],
            max_tokens: 1,
        });

        return { isValid: true };
    } catch (error: unknown) {
        const err = error as { status?: number; message?: string };
        const status = err?.status;
        if (status === 401) {
            return { isValid: false, error: 'Недействительный API-ключ (401)' };
        }
        return { isValid: false, error: err.message || 'Ошибка валидации' };
    }
}

/**
 * Client-side Logger Helper
 *
 * Logs to the browser console at the appropriate level.
 * Error-level messages are also forwarded to the Tauri plugin-log so they
 * appear in the on-disk app.log file and survive app restarts.
 */

/** Forward an error message to the Tauri on-disk log (best-effort). */
async function forwardErrorToTauri(text: string): Promise<void> {
    try {
        const { error: tauriError } = await import('@tauri-apps/plugin-log');
        await tauriError(text);
    } catch (_e) {
        // Not running inside Tauri (e.g. unit tests) — ignore
    }
}

export const logger = {
    info: (message: string, ...args: unknown[]) => {
        const text = formatMessage(message, args);
        console.log(text);
    },

    error: (message: string, ...args: unknown[]) => {
        const text = formatMessage(message, args);
        console.error(text);
        forwardErrorToTauri(text);
    },

    warn: (message: string, ...args: unknown[]) => {
        const text = formatMessage(message, args);
        console.warn(text);
    },

    debug: (message: string, ...args: unknown[]) => {
        // Debug logs only in development
        if (process.env.NODE_ENV === 'development') {
            console.debug(formatMessage(message, args));
        }
    }
};

function formatMessage(message: string, args: unknown[]): string {
    if (args.length === 0) return message;
    try {
        return message + ' ' + args.map(a =>
            a instanceof Error ? (a.stack || a.message) :
                typeof a === 'object' ? JSON.stringify(a) :
                    String(a)
        ).join(' ');
    } catch (_e) {
        return message + ' [Circular/Unserializable]';
    }
}

/**
 * Structured Logger for RheoLab
 * Replaces console.log with level-based logging
 * 
 * Features:
 * - Log levels (DEBUG, INFO, WARN, ERROR)
 * - Automatic prefix with module name
 * - Production mode suppresses DEBUG logs
 * - Emoji indicators for quick visual scanning
 */

export type LogLevel = 'DEBUG' | 'INFO' | 'WARN' | 'ERROR';

interface LoggerConfig {
    level: LogLevel;
    enabled: boolean;
}

const LOG_LEVELS: Record<LogLevel, number> = {
    DEBUG: 0,
    INFO: 1,
    WARN: 2,
    ERROR: 3
};

const LOG_EMOJI: Record<LogLevel, string> = {
    DEBUG: '🔍',
    INFO: '📋',
    WARN: '⚠️',
    ERROR: '❌'
};

// Default config - can be overridden
let config: LoggerConfig = {
    level: process.env.NODE_ENV === 'production' ? 'INFO' : 'DEBUG',
    enabled: true
};

/**
 * Configure the logger
 */
export function configureLogger(newConfig: Partial<LoggerConfig>): void {
    config = { ...config, ...newConfig };
}

/**
 * Get current log level
 */
export function getLogLevel(): LogLevel {
    return config.level;
}

/**
 * Check if a log level should be printed
 */
function shouldLog(level: LogLevel): boolean {
    if (!config.enabled) return false;
    return LOG_LEVELS[level] >= LOG_LEVELS[config.level];
}

/**
 * Format log message with module prefix
 */
function formatMessage(module: string, message: string, level: LogLevel): string {
    const emoji = LOG_EMOJI[level];
    return `${emoji} [${module}] ${message}`;
}

/**
 * Create a namespaced logger for a specific module
 */
export function createLogger(module: string) {
    return {
        debug: (message: string, ...args: unknown[]) => {
            if (shouldLog('DEBUG')) {
                console.log(formatMessage(module, message, 'DEBUG'), ...args);
                emitLog('DEBUG', module, message, args);
            }
        },

        info: (message: string, ...args: unknown[]) => {
            if (shouldLog('INFO')) {
                console.log(formatMessage(module, message, 'INFO'), ...args);
                emitLog('INFO', module, message, args);
            }
        },

        warn: (message: string, ...args: unknown[]) => {
            if (shouldLog('WARN')) {
                console.warn(formatMessage(module, message, 'WARN'), ...args);
                emitLog('WARN', module, message, args);
            }
        },

        error: (message: string, ...args: unknown[]) => {
            if (shouldLog('ERROR')) {
                console.error(formatMessage(module, message, 'ERROR'), ...args);
                emitLog('ERROR', module, message, args);
            }
        },

        /**
         * Log with custom emoji (for special cases like physics, success, etc.)
         */
        custom: (emoji: string, message: string, ...args: unknown[]) => {
            if (shouldLog('INFO')) {
                console.log(`${emoji} [${module}] ${message}`, ...args);
                emitLog('INFO', module, `${emoji} ${message}`, args);
            }
        }
    };
}

// Pre-configured loggers for common modules
export const logger = {
    parser: createLogger('RheoParser'),
    physics: createLogger('PhysicsEngine'),
    instrument: createLogger('InstrumentDetector'),
    geometry: createLogger('GeometryVerifier'),
    header: createLogger('HeaderDetector'),
    sheet: createLogger('SheetScanner'),
    ai: createLogger('AI Client'),
    aiMapper: createLogger('AIColumnMapper'),
    sst: createLogger('SST Detector'),
    pattern: createLogger('PatternDetector'),
    cycle: createLogger('CycleProcessor'),
    api: createLogger('API'),
    // Additional loggers for server-side modules
    secureStorage: createLogger('SecureStorage'),
    machineId: createLogger('MachineID'),
    licensing: createLogger('Licensing'),
    testFixtures: createLogger('TestFixtures'),
    reagents: createLogger('Reagents'),
    apiKeys: createLogger('APIKeys'),
    database: createLogger('Database'),
    auth: createLogger('Auth'),
    admin: createLogger('Admin'),
    experiments: createLogger('Experiments'),
    diagnostics: createLogger('Diagnostics'),
    waterSources: createLogger('WaterSources'),
    importExport: createLogger('ImportExport'),
    app: createLogger('App')
};

// --- Log Subscription System ---

export interface LogEntry {
    timestamp: number;
    level: LogLevel;
    module: string;
    message: string;
    args?: unknown[];
}

type LogListener = (entry: LogEntry) => void;
const listeners: Set<LogListener> = new Set();

export function subscribeToLogs(listener: LogListener): () => void {
    listeners.add(listener);
    return () => listeners.delete(listener);
}

function emitLog(level: LogLevel, module: string, message: string, args: unknown[]) {
    const entry: LogEntry = {
        timestamp: Date.now(),
        level,
        module,
        message,
        args: args.length > 0 ? args : undefined
    };
    listeners.forEach(listener => listener(entry));
}

import { extractFilenameMetadata } from '@/lib/parsing/filename-metadata';
import { getBridge } from '@/lib/tauri/bridge';
import { getActiveGroqKey } from '@/lib/api-keys/helpers';
import { toFiniteNumber } from '@/lib/utils/numbers';
import type { ParseResult, ParsedBy } from '@/types';

export const MAX_FILE_SIZE = 10 * 1024 * 1024;
const ALLOWED_EXTENSIONS = ['xlsx', 'xls', 'csv', 'txt', 'dat'];
const TAURI_PARSE_RETRY_DELAY_MS = 150;

interface ParseOptions {
  aiModel?: string;
  apiKey?: string;
  /** Force AI column mapping even when heuristic parser succeeds. Skips native parser. */
  forceAI?: boolean;
}

/** Mutable context accumulated during a single parse call. */
interface ParseContext {
  parsedBy: ParsedBy;
  warnings: string[];
}

type FilenameMetadata = NonNullable<ParseResult['metadata']['filenameMetadata']>;
type NumericValue = number | string | null | undefined;
type UnknownRecord = Record<string, unknown>;

function delay(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function normalizeDate(value: unknown): Date | undefined {
  if (!value) {
    return undefined;
  }
  if (value instanceof Date) {
    return value;
  }
  if (typeof value !== 'string') {
    return undefined;
  }
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? undefined : parsed;
}

function asRecord(value: unknown): UnknownRecord | null {
  if (!value || typeof value !== 'object') {
    return null;
  }
  return value as UnknownRecord;
}

function readNumber(record: UnknownRecord, keys: string[], fallback = 0): number {
  for (const key of keys) {
    if (key in record) {
      return toFiniteNumber(record[key] as NumericValue, fallback);
    }
  }
  return fallback;
}

function normalizeDataPoints(data: unknown): ParseResult['data'] {
  if (!Array.isArray(data)) {
    return [];
  }

  return data.map((point) => {
    const record = asRecord(point) ?? {};
    return {
      time_sec: readNumber(record, ['time_sec', 'timeSec', 'time'], 0),
      viscosity_cp: readNumber(record, ['viscosity_cp', 'viscosityCp', 'viscosity'], 0),
      temperature_c: readNumber(record, ['temperature_c', 'temperatureC', 'temperature'], 0),
      speed_rpm: readNumber(record, ['speed_rpm', 'speedRpm', 'rpm'], 0),
      shear_rate_s1: readNumber(record, ['shear_rate_s1', 'shearRateS1', 'shear_rate', 'shearRate'], 0),
      shear_stress_pa: readNumber(record, ['shear_stress_pa', 'shearStressPa', 'shear_stress', 'shearStress'], 0),
      pressure_bar: readNumber(record, ['pressure_bar', 'pressureBar', 'pressure'], 0),
      bath_temperature_c: readNumber(record, ['bath_temperature_c', 'bathTemperatureC'], 0) || undefined,
    };
  });
}

function normalizeTimeRange(value: unknown): ParseResult['summary']['timeRange'] | undefined {
  const record = asRecord(value);
  if (!record) {
    return undefined;
  }

  const start = readNumber(record, ['start'], 0);
  const end = readNumber(record, ['end'], start);
  const durationMinutes = readNumber(
    record,
    ['durationMinutes', 'duration_minutes'],
    (end - start) / 60,
  );

  return { start, end, durationMinutes };
}

function normalizeRangeWithAvg(
  value: unknown,
): ParseResult['summary']['viscosityRange'] | ParseResult['summary']['temperatureRange'] | undefined {
  const record = asRecord(value);
  if (!record) {
    return undefined;
  }

  const min = readNumber(record, ['min'], 0);
  const max = readNumber(record, ['max'], min);
  const avgPresent = 'avg' in record;

  return {
    min,
    max,
    ...(avgPresent ? { avg: readNumber(record, ['avg'], min) } : {}),
  };
}

function normalizeRange(value: unknown): ParseResult['summary']['pressureRange'] | undefined {
  const record = asRecord(value);
  if (!record) {
    return undefined;
  }

  return {
    min: readNumber(record, ['min'], 0),
    max: readNumber(record, ['max'], 0),
  };
}

function normalizeSummary(summary: unknown, data: ParseResult['data']): ParseResult['summary'] {
  const record = asRecord(summary);
  if (!record) {
    return buildSummary(data);
  }

  const normalized = {
    pointCount: Math.max(
      0,
      Math.round(readNumber(record, ['pointCount', 'point_count'], data.length)),
    ),
    timeRange: normalizeTimeRange(record.timeRange ?? record.time_range),
    viscosityRange: normalizeRangeWithAvg(record.viscosityRange ?? record.viscosity_range),
    temperatureRange: normalizeRangeWithAvg(record.temperatureRange ?? record.temperature_range),
    pressureRange: normalizeRange(record.pressureRange ?? record.pressure_range),
  };

  if (
    normalized.pointCount <= 0 &&
    !normalized.timeRange &&
    !normalized.viscosityRange &&
    !normalized.temperatureRange &&
    !normalized.pressureRange
  ) {
    return buildSummary(data);
  }

  return normalized;
}

function normalizeParseResult(result: ParseResult): ParseResult {
  const data = normalizeDataPoints((result as { data?: unknown }).data);
  const summary = normalizeSummary((result as { summary?: unknown }).summary, data);
  const testDate = normalizeDate(result.metadata?.testDate);
  const calibrationDate = normalizeDate(result.metadata?.calibration?.calibrationDate);

  return {
    ...result,
    data,
    summary,
    metadata: {
      ...result.metadata,
      testDate,
      calibration: result.metadata.calibration
        ? {
          ...result.metadata.calibration,
          calibrationDate: calibrationDate ?? result.metadata.calibration.calibrationDate,
        }
        : undefined,
    },
  };
}

function hasFilenameMetadata(metadata: FilenameMetadata): boolean {
  return Boolean(
    metadata.testId ||
      metadata.testType ||
      metadata.testTypeFull ||
      metadata.fieldName ||
      metadata.wellNumber ||
      metadata.operatorName ||
      metadata.destination ||
      metadata.waterSource ||
      metadata.temperature !== undefined ||
      metadata.createdBy ||
      metadata.laboratoryName ||
      (metadata.recipe && metadata.recipe.length > 0),
  );
}

function mergeFilenameMetadata(
  primary?: FilenameMetadata,
  secondary?: FilenameMetadata,
): FilenameMetadata | undefined {
  if (!primary && !secondary) {
    return undefined;
  }

  const merged: FilenameMetadata = {
    testId: primary?.testId ?? secondary?.testId,
    testType: primary?.testType ?? secondary?.testType,
    testTypeFull: primary?.testTypeFull ?? secondary?.testTypeFull,
    fieldName: primary?.fieldName ?? secondary?.fieldName,
    wellNumber: primary?.wellNumber ?? secondary?.wellNumber,
    operatorName: primary?.operatorName ?? secondary?.operatorName,
    destination: primary?.destination ?? secondary?.destination,
    waterSource:
      primary?.waterSource ??
      secondary?.waterSource ??
      primary?.destination ??
      secondary?.destination,
    temperature: primary?.temperature ?? secondary?.temperature,
    createdBy: primary?.createdBy ?? secondary?.createdBy,
    laboratoryName: primary?.laboratoryName ?? secondary?.laboratoryName,
    recipe:
      primary?.recipe && primary.recipe.length > 0
        ? primary.recipe
        : secondary?.recipe,
  };

  return hasFilenameMetadata(merged) ? merged : undefined;
}

async function enrichParseResult(
  result: ParseResult,
  filename: string,
): Promise<ParseResult> {
  const filenameExtraction = await extractFilenameMetadata(filename);
  const filenameMetadata = mergeFilenameMetadata(
    result.metadata.filenameMetadata,
    filenameExtraction.filenameMetadata,
  );

  return normalizeParseResult({
    ...result,
    metadata: {
      ...result.metadata,
      filenameMetadata,
      testDate: result.metadata.testDate ?? filenameExtraction.testDate,
    },
  });
}

function isTauriParsingUnavailable(error: unknown): boolean {
  const message = (error instanceof Error ? error.message : String(error)).toLowerCase();
  return (
    message.includes('not running in tauri') ||
    message.includes('tauri_internals') ||
    message.includes('__tauri_internals__') ||
    message.includes('window is not defined') ||
    (message.includes('cannot read') && message.includes('invoke')) ||
    message.includes('unknown ipc command') ||
    message.includes('command parsing_parse_file not found') ||
    (message.includes('parsing_parse_file') && message.includes('not found'))
  );
}

/**
 * Returns true when the native parser executed but could not extract data.
 * These failures should fall through to WASM+AI when an API key is available.
 */
function isNativeParseDataFailure(error: unknown): boolean {
  const message = (error instanceof Error ? error.message : String(error)).toLowerCase();
  return (
    message.includes('no valid data points') ||
    message.includes('native parser error')
  );
}

async function parseViaTauriNative(file: File, buffer: ArrayBuffer, options?: ParseOptions): Promise<ParseResult> {
  const bridge = getBridge();
  // On Tauri desktop, the File object contains a native .path property.
  // Passing filePath lets Rust read the file directly — avoids 8× array conversion over IPC (~120 MB → ~10 MB per parse).
  const filePath = (file as unknown as { path?: string }).path;
  const request = filePath
    ? { filename: file.name, filePath, forceAi: options?.forceAI, aiModel: options?.aiModel, apiKey: options?.apiKey }
    : {
        filename: file.name,
        // Bytes pre-read by caller — avoids re-reading the file on retries (#32)
        bytes: Array.from(new Uint8Array(buffer)),
        forceAi: options?.forceAI,
        aiModel: options?.aiModel,
        apiKey: options?.apiKey,
      };
  const response = await bridge.parsing.parseFile(request);
  return normalizeParseResult(response as unknown as ParseResult);
}

function assertSupportedFile(file: File): void {
  if (file.size > MAX_FILE_SIZE) {
    throw new Error(`File too large. Maximum size: ${MAX_FILE_SIZE / 1024 / 1024}MB`);
  }

  const ext = file.name.split('.').pop()?.toLowerCase();
  if (!ext || !ALLOWED_EXTENSIONS.includes(ext)) {
    throw new Error(`Unsupported file type: .${ext}`);
  }
}

function buildSummary(data: ParseResult['data']): ParseResult['summary'] {
  if (!data || data.length === 0) {
    return {
      pointCount: 0,
      timeRange: { start: 0, end: 0, durationMinutes: 0 },
      viscosityRange: { min: 0, max: 0, avg: 0 },
      temperatureRange: { min: 0, max: 0, avg: 0 },
    };
  }

  // Single-pass iteration — Math.min/max spread throws RangeError on arrays
  // larger than ~65k elements, and creates 4 unnecessary intermediate arrays.
  let minTime = Infinity,  maxTime = -Infinity;
  let minVisc = Infinity,  maxVisc = -Infinity,  sumVisc = 0;
  let minTemp = Infinity,  maxTemp = -Infinity,  sumTemp = 0;
  let minPres = Infinity,  maxPres = -Infinity,  hasPressure = false;

  for (const p of data) {
    if (p.time_sec < minTime) minTime = p.time_sec;
    if (p.time_sec > maxTime) maxTime = p.time_sec;
    if (p.viscosity_cp < minVisc) minVisc = p.viscosity_cp;
    if (p.viscosity_cp > maxVisc) maxVisc = p.viscosity_cp;
    sumVisc += p.viscosity_cp;
    if (p.temperature_c < minTemp) minTemp = p.temperature_c;
    if (p.temperature_c > maxTemp) maxTemp = p.temperature_c;
    sumTemp += p.temperature_c;
    if ((p.pressure_bar || 0) > 0) {
      const pbar = p.pressure_bar!;
      if (pbar < minPres) minPres = pbar;
      if (pbar > maxPres) maxPres = pbar;
      hasPressure = true;
    }
  }

  const n = data.length;
  const durationMinutes = Math.round(((maxTime - minTime) / 60) * 10) / 10;

  return {
    pointCount: n,
    timeRange: { start: minTime, end: maxTime, durationMinutes },
    viscosityRange: {
      min: Math.round(minVisc * 100) / 100,
      max: Math.round(maxVisc * 100) / 100,
      avg: Math.round((sumVisc / n) * 100) / 100,
    },
    temperatureRange: {
      min: Math.round(minTemp * 10) / 10,
      max: Math.round(maxTemp * 10) / 10,
      avg: Math.round((sumTemp / n) * 10) / 10,
    },
    ...(hasPressure && {
      pressureRange: {
        min: Math.round(minPres * 100) / 100,
        max: Math.round(maxPres * 100) / 100,
      },
    }),
  };
}

/**
 * Desktop file parsing via Tauri commands.
 *
 * Parse chain: Tauri native → (retry) → WASM → legacy API.
 * Each transition is recorded in `parsedBy` / `warnings`.
 */
export async function parseRheologyFile(
  file: File,
  options?: ParseOptions,
): Promise<ParseResult> {
  assertSupportedFile(file);
  const bridge = getBridge();
  const desktopRuntime = bridge.platform === 'tauri';

  // Resolve API key once — callers no longer need to fetch it themselves.
  const resolvedOptions: ParseOptions = {
    ...options,
    apiKey: options?.apiKey ?? await getActiveGroqKey(),
  };

  if (import.meta.env.DEV) console.log('[parseRheologyFile] resolvedOptions:', {
    forceAI: resolvedOptions.forceAI,
    aiModel: resolvedOptions.aiModel,
    hasApiKey: !!resolvedOptions.apiKey,
  });

  // Early guard: when Force AI is requested, an API key is required.
  if (resolvedOptions.forceAI && !resolvedOptions.apiKey) {
    console.warn('[parseRheologyFile] forceAI=true but no API key resolved! AI parsing will fail.');
    throw new Error(
      'Принудительный AI-парсинг включён, но Groq API ключ не найден. ' +
      'Добавьте ключ в Настройки → API Ключи.',
    );
  }

  const ctx: ParseContext = { parsedBy: 'native', warnings: [] };

  // Read the file buffer once — reused for native and WASM paths to avoid
  // multiple file reads on retry/fallback chains (#32 fix)
  const fileBuffer = await file.arrayBuffer();

  // On Tauri desktop with forceAI, route directly through the native Rust parser
  // (which calls Groq HTTP API internally). WASM is disabled at build time in Tauri
  // so we must not fall through to the WASM path in desktop mode.
  if (desktopRuntime && resolvedOptions?.forceAI) {
    const nativeResult = await parseViaTauriNative(file, fileBuffer, resolvedOptions);
    ctx.parsedBy = 'native';
    return applyContext(await enrichParseResult(nativeResult, file.name), ctx);
  }

  // When AI is forced in browser (non-Tauri), skip the native parser and go
  // straight to the WASM+AI path so the AI column-mapping callback fires.
  if (!resolvedOptions?.forceAI) {
    try {
      const nativeResult = await parseViaTauriNative(file, fileBuffer, resolvedOptions);
      ctx.parsedBy = 'native';
      return applyContext(await enrichParseResult(nativeResult, file.name), ctx);
    } catch (nativeError) {
      let nativeUnavailableError: unknown = nativeError;

      // When the native parser ran but could not extract data and we have an
      // API key, skip retries and fall straight through to the WASM+AI path.
      const canRetryWithAI = isNativeParseDataFailure(nativeError) && !!resolvedOptions?.apiKey;

      if (!isTauriParsingUnavailable(nativeError) && !canRetryWithAI) {
        throw nativeError;
      }

      if (canRetryWithAI) {
        ctx.warnings.push(
          'Native parser found no data, falling through to WASM AI path',
        );
      } else if (desktopRuntime) {
        await delay(TAURI_PARSE_RETRY_DELAY_MS);
        try {
          const retriedNativeResult = await parseViaTauriNative(file, fileBuffer, resolvedOptions);
          ctx.parsedBy = 'native';
          return applyContext(await enrichParseResult(retriedNativeResult, file.name), ctx);
        } catch (retryError) {
          if (!isTauriParsingUnavailable(retryError)) {
            throw retryError;
          }
          nativeUnavailableError = retryError;
        }

        // Fall through to WASM instead of throwing hard error.
        // This also allows E2E tests (which mock __TAURI_INTERNALS__ but
        // reject parsing commands) to exercise the real WASM parser.
        const reason = nativeUnavailableError instanceof Error
          ? nativeUnavailableError.message
          : String(nativeUnavailableError);
        // ADR-0003: WASM fallback removed — fail hard if native is truly unavailable
        throw new Error(`Native parser unavailable: ${reason}`);
      }
    }
  } // end !forceAI block

  // ADR-0003: WASM fallback removed — this point is now unreachable since
  // native parsing is the only path in Tauri-only mode.
  throw new Error('Parsing pipeline exhausted: no parser available');
}

/** Stamp parsedBy + warnings onto a ParseResult. */
function applyContext(result: ParseResult, ctx: ParseContext): ParseResult {
  return {
    ...result,
    parsedBy: ctx.parsedBy,
    ...(ctx.warnings.length > 0 ? { warnings: ctx.warnings } : {}),
  };
}

import type { ParseResult } from '@/types';
import { parseExperimentFilename } from '@/lib/utils/smart-fill-utils';

type FilenameMetadata = NonNullable<ParseResult['metadata']['filenameMetadata']>;
type RecipeItem = NonNullable<FilenameMetadata['recipe']>[number];

interface ExtractFilenameMetadataResult {
  filenameMetadata?: FilenameMetadata;
  testDate?: Date;
}

const TEST_TYPE_MAP: Record<string, string> = {
  SST: 'Shear Stability Test',
  SWB: 'Shear sweep With Breaker',
  HST: 'High Shear Test',
  LVT: 'Low Viscosity Test',
};

const RECIPE_REGEX = /(\d+(?:\.\d+)?)\(([A-Za-z0-9-]+)\)/g;
const TEST_ID_REGEX = /^\d+$/;
const TEST_TYPE_REGEX = /^[A-Z]{2,4}$/;
const FIELD_DEST_REGEX = /([A-Za-zА-Яа-яёЁ]+)_\(([^)]+)\)/;
const TEMP_REGEX = /@(\d+)[CcСс]/;
const END_DATE_REGEX = /(\d{2})\.(\d{2})(?:\.(\d{2,4}))?$/;

function asString(value: unknown): string | undefined {
  if (typeof value !== 'string') {
    return undefined;
  }
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : undefined;
}

function asNumber(value: unknown): number | undefined {
  if (typeof value !== 'number' || Number.isNaN(value) || !Number.isFinite(value)) {
    return undefined;
  }
  return value;
}

function normalizeRecipeItems(items: unknown): RecipeItem[] | undefined {
  if (!Array.isArray(items)) {
    return undefined;
  }

  const normalized = items
    .map((item): RecipeItem | null => {
      if (!item || typeof item !== 'object') {
        return null;
      }
      const candidate = item as Record<string, unknown>;
      const abbreviation = asString(candidate.abbreviation);
      const concentration = asNumber(candidate.concentration);
      if (!abbreviation || concentration === undefined) {
        return null;
      }

      return {
        abbreviation,
        concentration,
        unit: asString(candidate.unit) || 'kg/m3',
        category: asString(candidate.category),
        reagentId: asString(candidate.reagentId),
        reagentName: asString(candidate.reagentName),
      };
    })
    .filter((item): item is RecipeItem => item !== null);

  return normalized.length > 0 ? normalized : undefined;
}

function hasMetadataValue(metadata: FilenameMetadata): boolean {
  return Boolean(
    metadata.testId ||
      metadata.testType ||
      metadata.testTypeFull ||
      metadata.fieldName ||
      metadata.wellNumber ||
      metadata.operatorName ||
      metadata.destination ||
      metadata.waterSource ||
      metadata.temperature !== undefined ||
      (metadata.recipe && metadata.recipe.length > 0),
  );
}

function parseDateFromFilename(baseName: string): Date | undefined {
  const match = baseName.match(END_DATE_REGEX);
  if (!match) {
    return undefined;
  }

  const day = Number.parseInt(match[1], 10);
  const month = Number.parseInt(match[2], 10);
  const rawYear = match[3];
  const year = rawYear
    ? rawYear.length === 2
      ? Number.parseInt(rawYear, 10) + 2000
      : Number.parseInt(rawYear, 10)
    : new Date().getFullYear();

  const date = new Date(year, month - 1, day);
  return Number.isNaN(date.getTime()) ? undefined : date;
}

function buildFallbackMetadata(filename: string): ExtractFilenameMetadataResult {
  const baseName = filename.replace(/\.[^/.]+$/, '');
  const metadata: FilenameMetadata = {};

  const parts = baseName.split(/\s+/).filter(Boolean);
  if (parts.length > 0 && TEST_ID_REGEX.test(parts[0])) {
    metadata.testId = parts[0];
  }
  if (parts.length > 1 && TEST_TYPE_REGEX.test(parts[1])) {
    metadata.testType = parts[1];
    metadata.testTypeFull = TEST_TYPE_MAP[parts[1]] || 'Unknown Test Type';
  }

  const fieldDestMatch = baseName.match(FIELD_DEST_REGEX);
  if (fieldDestMatch) {
    metadata.fieldName = fieldDestMatch[1];
    metadata.destination = fieldDestMatch[2].replace(/_/g, ' ');
    metadata.waterSource = metadata.destination;
  }

  const tempMatch = baseName.match(TEMP_REGEX);
  if (tempMatch) {
    metadata.temperature = Number.parseInt(tempMatch[1], 10);
  }

  const recipe: RecipeItem[] = [];
  RECIPE_REGEX.lastIndex = 0;
  for (const match of baseName.matchAll(RECIPE_REGEX)) {
    const concentration = Number.parseFloat(match[1]);
    const abbreviation = match[2];
    if (!Number.isFinite(concentration) || !abbreviation) {
      continue;
    }
    recipe.push({
      abbreviation,
      concentration,
      unit: 'kg/m3',
    });
  }
  if (recipe.length > 0) {
    metadata.recipe = recipe;
  }

  const heuristicMetadata = parseExperimentFilename(filename);
  if (!metadata.fieldName && heuristicMetadata.fieldName) {
    metadata.fieldName = heuristicMetadata.fieldName;
  }
  if (!metadata.wellNumber && heuristicMetadata.wellNumber) {
    metadata.wellNumber = heuristicMetadata.wellNumber;
  }
  if (!metadata.operatorName && heuristicMetadata.operatorName) {
    metadata.operatorName = heuristicMetadata.operatorName;
  }
  if (metadata.temperature === undefined && heuristicMetadata.temperature !== undefined) {
    metadata.temperature = heuristicMetadata.temperature;
  }

  const testDate = parseDateFromFilename(baseName) || heuristicMetadata.testDate;
  return {
    filenameMetadata: hasMetadataValue(metadata) ? metadata : undefined,
    testDate,
  };
}

/**
 * Best-effort filename metadata extraction using local regex heuristics.
 *
 * ADR-0003: WASM parser removed — in Tauri desktop the Rust native parser
 * handles filename metadata via IPC. This function is a local-only fallback.
 */
export async function extractFilenameMetadata(filename: string): Promise<ExtractFilenameMetadataResult> {
  return buildFallbackMetadata(filename);
}

/**
 * Chart Settings Store
 * Global settings for chart visualization (Zustand with persist)
 * Each curve has individual color, width and style settings
 *
 * Types and defaults live in separate modules; re-exported here for
 * backward-compatible imports from '@/lib/store/chart-settings-store'.
 */

import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import { debugLog } from '@/lib/utils/debug-logger';

// Re-export types and defaults for backward compatibility
export type {
    LineWidth,
    LineStyle,
    LineAxis,
    DownsampleMode,
    ComparisonAxisMode,
    LineSettings,
    ChartLineSettings,
    ChartPrecision,
    ChartSettings,
} from './chart-settings-types';
export {
    DEFAULT_LINE_SETTINGS,
    DEFAULT_REPORT_LINE_SETTINGS,
    DEFAULT_CHART_SETTINGS,
    DEFAULT_REPORT_SETTINGS,
} from './chart-settings-defaults';

import type {
    LineWidth,
    LineStyle,
    LineAxis,
    DownsampleMode,
    ComparisonAxisMode,
    LineSettings,
    ChartLineSettings,
    ChartPrecision,
    ChartSettings,
} from './chart-settings-types';
import {
    DEFAULT_LINE_SETTINGS,
    DEFAULT_REPORT_LINE_SETTINGS,
    DEFAULT_CHART_SETTINGS,
    DEFAULT_REPORT_SETTINGS,
} from './chart-settings-defaults';

// === Line Key Type ===
export type LineKey = keyof ChartLineSettings;

// === Store State Interface ===
interface ChartSettingsState {
    settings: ChartSettings;
    reportSettings: ChartSettings;
    
    // Display settings methods
    setSettings: (settings: Partial<ChartSettings>) => void;
    setLineSettings: (lineKey: LineKey, lineSettings: Partial<LineSettings>) => void;
    setPrecision: (precision: Partial<ChartPrecision>) => void;
    resetToDefaults: () => void;
    
    // Report settings methods
    setReportSettings: (settings: Partial<ChartSettings>) => void;
    setReportLineSettings: (lineKey: LineKey, lineSettings: Partial<LineSettings>) => void;
    setReportPrecision: (precision: Partial<ChartPrecision>) => void;
    resetReportToDefaults: () => void;
    copyDisplayToReport: () => void;
    
    // Export/Import
    exportSettings: () => string;
    importSettings: (json: string) => boolean;
}

// === Debounced localStorage adapter ===
// Chart settings are read on every zoom/pan event; without debouncing, every
// state update would synchronously serialize and write ~5 KB to localStorage.
// 500 ms debounce coalesces rapid successive writes into a single flush.
function makeDebouncedStorage(delayMs = 500) {
    let timer: ReturnType<typeof setTimeout> | null = null;
    return {
        getItem: (name: string) => localStorage.getItem(name),
        setItem: (name: string, value: string) => {
            if (timer !== null) clearTimeout(timer);
            timer = setTimeout(() => localStorage.setItem(name, value), delayMs);
        },
        removeItem: (name: string) => localStorage.removeItem(name),
    };
}

/** JSON storage with a 500 ms write debounce — prevents flooding localStorage on every zoom event. */
const debouncedJsonStorage = createJSONStorage(() => makeDebouncedStorage(500));

// === Store Implementation ===
export const useChartSettingsStore = create<ChartSettingsState>()(
    persist(
        (set, get) => ({
            settings: { ...DEFAULT_CHART_SETTINGS },
            reportSettings: { ...DEFAULT_REPORT_SETTINGS },

            // === Display Settings Methods ===
            setSettings: (newSettings) =>
                set((state) => ({
                    settings: { ...state.settings, ...newSettings },
                })),

            setLineSettings: (lineKey, lineSettings) =>
                set((state) => ({
                    settings: {
                        ...state.settings,
                        lines: {
                            ...state.settings.lines,
                            [lineKey]: { ...state.settings.lines[lineKey], ...lineSettings },
                        },
                    },
                })),

            setPrecision: (precision) =>
                set((state) => ({
                    settings: {
                        ...state.settings,
                        precision: { ...state.settings.precision, ...precision },
                    },
                })),

            resetToDefaults: () =>
                set({ settings: structuredClone(DEFAULT_CHART_SETTINGS) }),

            // === Report Settings Methods ===
            setReportSettings: (newSettings) =>
                set((state) => ({
                    reportSettings: { ...state.reportSettings, ...newSettings },
                })),

            setReportLineSettings: (lineKey, lineSettings) =>
                set((state) => ({
                    reportSettings: {
                        ...state.reportSettings,
                        lines: {
                            ...state.reportSettings.lines,
                            [lineKey]: { ...state.reportSettings.lines[lineKey], ...lineSettings },
                        },
                    },
                })),

            setReportPrecision: (precision) =>
                set((state) => ({
                    reportSettings: {
                        ...state.reportSettings,
                        precision: { ...state.reportSettings.precision, ...precision },
                    },
                })),

            resetReportToDefaults: () =>
                set({ reportSettings: structuredClone(DEFAULT_REPORT_SETTINGS) }),

            copyDisplayToReport: () =>
                set((state) => ({
                    reportSettings: { 
                        ...structuredClone(state.settings),
                        animationsEnabled: false,
                        tooltipEnabled: false,
                    },
                })),

            // === Export/Import ===
            exportSettings: () => {
                const { settings, reportSettings } = get();
                return JSON.stringify({ display: settings, report: reportSettings }, null, 2);
            },

            importSettings: (json: string) => {
                try {
                    const parsed = JSON.parse(json);
                    
                    if (parsed.display && parsed.report) {
                        set({
                            settings: {
                                ...DEFAULT_CHART_SETTINGS,
                                ...parsed.display,
                                lines: { ...DEFAULT_LINE_SETTINGS, ...parsed.display.lines },
                                precision: { ...DEFAULT_CHART_SETTINGS.precision, ...parsed.display.precision },
                            },
                            reportSettings: {
                                ...DEFAULT_REPORT_SETTINGS,
                                ...parsed.report,
                                lines: { ...DEFAULT_REPORT_LINE_SETTINGS, ...parsed.report.lines },
                                precision: { ...DEFAULT_REPORT_SETTINGS.precision, ...parsed.report.precision },
                            },
                        });
                    } else if (parsed.lines && parsed.precision) {
                        // Old format - apply to display settings only
                        set({
                            settings: {
                                ...DEFAULT_CHART_SETTINGS,
                                ...parsed,
                                lines: { ...DEFAULT_LINE_SETTINGS, ...parsed.lines },
                                precision: { ...DEFAULT_CHART_SETTINGS.precision, ...parsed.precision },
                            },
                        });
                    } else {
                        console.error('Invalid chart settings format');
                        return false;
                    }
                    
                    return true;
                } catch (e) {
                    console.error('Failed to import chart settings:', e);
                    return false;
                }
            },
        }),
        {
            name: 'rheolab-chart-settings',
            storage: debouncedJsonStorage,
            version: 7, // Increment when structure changes
            // merge is called on every hydration — guarantees all default keys
            // (e.g. bathTemperature) are present even in old persisted states.
            merge: (persisted, current) => {
                const p = (persisted ?? {}) as Record<string, unknown>;
                const pSettings = (p.settings ?? {}) as Record<string, unknown>;
                const pReport  = (p.reportSettings ?? {}) as Record<string, unknown>;
                return {
                    ...current,
                    ...p,
                    settings: {
                        ...current.settings,
                        ...pSettings,
                        lines: {
                            ...DEFAULT_LINE_SETTINGS,
                            ...((pSettings.lines ?? {}) as object),
                        },
                    },
                    reportSettings: {
                        ...current.reportSettings,
                        ...pReport,
                        // Always enforce report-only fields regardless of persisted value
                        tooltipEnabled: false,
                        animationsEnabled: false,
                        lines: {
                            ...DEFAULT_REPORT_LINE_SETTINGS,
                            ...((pReport.lines ?? {}) as object),
                        },
                    },
                };
            },
            migrate: (persistedState: unknown, version: number) => {
                const state = persistedState as Record<string, unknown>;

                // Migration to v7: set reportSettings.lines.shearRate.axis to 'right'
                // (default was 'left', but Rust PDF renderer always puts shear rate on right
                // in individual mode — preview and PDF must match)
                if (version < 7) {
                    const r = state?.reportSettings as Record<string, unknown> | undefined;
                    const rLines = r?.lines as Record<string, unknown> | undefined;
                    const rShearRate = rLines?.shearRate as Record<string, unknown> | undefined;
                    if (rShearRate && rShearRate.axis === 'left') {
                        rShearRate.axis = 'right';
                    }
                }

                // Migration to v6: add bathTemperature to existing line settings
                if (version < 6) {
                    const s = state?.settings as Record<string, unknown> | undefined;
                    const r = state?.reportSettings as Record<string, unknown> | undefined;
                    const sLines = s?.lines as Record<string, unknown> | undefined;
                    const rLines = r?.lines as Record<string, unknown> | undefined;
                    if (sLines && !('bathTemperature' in sLines)) {
                        sLines.bathTemperature = { ...DEFAULT_LINE_SETTINGS.bathTemperature };
                    }
                    if (rLines && !('bathTemperature' in rLines)) {
                        rLines.bathTemperature = { ...DEFAULT_REPORT_LINE_SETTINGS.bathTemperature };
                    }
                }

                // Migration to v5: reset comparisonAxisMode to 'individual' (new default) if still at v4 default
                if (version < 5) {
                    const s = state?.settings as Record<string, unknown> | undefined;
                    const r = state?.reportSettings as Record<string, unknown> | undefined;
                    // Only reset if not explicitly customised (v4 set 'shared' as migration default)
                    if (s && s.comparisonAxisMode === 'shared') s.comparisonAxisMode = 'individual';
                    if (r && r.comparisonAxisMode === 'shared') r.comparisonAxisMode = 'individual';
                }

                // Migration to v4: add comparisonAxisMode to existing settings
                if (version < 4) {
                    const s = state?.settings as Record<string, unknown> | undefined;
                    const r = state?.reportSettings as Record<string, unknown> | undefined;
                    if (s && !('comparisonAxisMode' in s)) {
                        s.comparisonAxisMode = 'shared';
                    }
                    if (r && !('comparisonAxisMode' in r)) {
                        r.comparisonAxisMode = 'shared';
                    }
                }

                // Migration to v3: add downsampleMode to existing settings
                if (version < 3) {
                    const s = state?.settings as Record<string, unknown> | undefined;
                    const r = state?.reportSettings as Record<string, unknown> | undefined;
                    if (s && !('downsampleMode' in s)) {
                        s.downsampleMode = 'smart';
                    }
                    if (r && !('downsampleMode' in r)) {
                        r.downsampleMode = 'off';
                    }
                }

                // Migration from v1 (old format with colors/visibility) to v2 (lines)
                if (version < 2) {
                    debugLog('ChartSettings', 'Migrating from v1 to v2...');
                    
                    // Check if old format exists
                    const oldSettings = state?.settings as Record<string, unknown> | undefined;
                    
                    // If old format has 'colors' instead of 'lines', migrate
                    if (oldSettings && 'colors' in oldSettings && !('lines' in oldSettings)) {
                        const oldColors = oldSettings.colors as Record<string, string> | undefined;
                        const oldVisibility = oldSettings.visibility as Record<string, boolean> | undefined;
                        
                        // Create new lines structure from old format
                        const newLines: ChartLineSettings = {
                            viscosity: {
                                color: oldColors?.viscosity || DEFAULT_LINE_SETTINGS.viscosity.color,
                                width: (oldSettings.lineWidth as LineWidth) || 2,
                                style: (oldSettings.lineStyle as LineStyle) || 'solid',
                                visible: true,
                                axis: 'left',
                            },
                            temperature: {
                                color: oldColors?.temperature || DEFAULT_LINE_SETTINGS.temperature.color,
                                width: (oldSettings.lineWidth as LineWidth) || 2,
                                style: (oldSettings.lineStyle as LineStyle) || 'solid',
                                visible: oldVisibility?.temperature ?? true,
                                axis: 'right',
                            },
                            shearRate: {
                                color: oldColors?.shearRate || DEFAULT_LINE_SETTINGS.shearRate.color,
                                width: (oldSettings.lineWidth as LineWidth) || 2,
                                style: (oldSettings.lineStyle as LineStyle) || 'solid',
                                visible: oldVisibility?.shearRate ?? true,
                                axis: 'left',
                            },
                            pressure: {
                                color: oldColors?.pressure || DEFAULT_LINE_SETTINGS.pressure.color,
                                width: (oldSettings.lineWidth as LineWidth) || 2,
                                style: (oldSettings.lineStyle as LineStyle) || 'solid',
                                visible: oldVisibility?.pressure ?? false,
                                axis: 'right',
                            },
                            rpm: {
                                color: oldColors?.rpm || DEFAULT_LINE_SETTINGS.rpm.color,
                                width: (oldSettings.lineWidth as LineWidth) || 2,
                                style: (oldSettings.lineStyle as LineStyle) || 'solid',
                                visible: oldVisibility?.rpm ?? false,
                                axis: 'left',
                            },
                            // bathTemperature was not in v1 — use the default settings
                            bathTemperature: { ...DEFAULT_LINE_SETTINGS.bathTemperature },
                        };
                        
                        return {
                            settings: {
                                ...DEFAULT_CHART_SETTINGS,
                                lines: newLines,
                                precision: oldSettings.precision || DEFAULT_CHART_SETTINGS.precision,
                                showGridLines: oldSettings.showGridLines ?? true,
                                gridOpacity: oldSettings.gridOpacity ?? 0.5,
                                animationsEnabled: oldSettings.animationsEnabled ?? true,
                                tooltipEnabled: oldSettings.tooltipEnabled ?? true,
                            },
                            reportSettings: DEFAULT_REPORT_SETTINGS,
                        };
                    }
                    
                    // If completely broken, return defaults
                    if (!oldSettings?.lines) {
                        return {
                            settings: DEFAULT_CHART_SETTINGS,
                            reportSettings: DEFAULT_REPORT_SETTINGS,
                        };
                    }
                }
                
                return state;
            },
        }
    )
);

// === Helper: Get stroke dasharray for line style ===
export function getStrokeDasharray(style: LineStyle): string | undefined {
    switch (style) {
        case 'dashed':
            return '5 5';
        case 'dotted':
            return '2 2';
        default:
            return undefined;
    }
}

// === Helper: Format value with precision ===
export function formatWithPrecision(value: number | undefined, precision: number): string {
    if (value === undefined || value === null) return '—';
    if (value === 0) return (0).toFixed(precision);
    return value.toFixed(precision);
}

/**
 * Debug Logger
 * 
 * Feature-flagged логирование для замены console.log.
 * Логи выводятся только при DEBUG=true или NODE_ENV=development.
 * 
 * Использование:
 * ```ts
 * import { debugLog, debugWarn } from '@/lib/utils/debug-logger';
 * debugLog('LicenseStore', 'Initialized:', result);
 * debugWarn('Parser', 'Unknown format');
 * ```
 */

/**
 * Проверяет, включен ли debug режим
 */
export function isDebugEnabled(): boolean {
  // В браузере (Vite env)
  if (typeof window !== 'undefined') {
    return (
      import.meta.env.DEV ||
      import.meta.env.VITE_DEBUG === 'true' ||
      localStorage.getItem('DEBUG') === 'true'
    );
  }

  // Fallback для SSR/Node.js контекста (не используется в Tauri)
  return false;
}

/**
 * Debug log - выводит только в debug режиме
 * @param category - категория/модуль (например 'LicenseStore', 'WasmEngine')
 * @param args - аргументы для логирования
 */
export function debugLog(category: string, ...args: unknown[]): void {
  if (isDebugEnabled()) {
    console.log(`[${category}]`, ...args);
  }
}

/**
 * Debug warn - выводит только в debug режиме
 * @param category - категория/модуль
 * @param args - аргументы для логирования
 */
export function debugWarn(category: string, ...args: unknown[]): void {
  if (isDebugEnabled()) {
    console.warn(`[${category}]`, ...args);
  }
}

/**
 * Debug error - выводит ВСЕГДА (ошибки важны)
 * @param category - категория/модуль
 * @param args - аргументы для логирования
 */
export function debugError(category: string, ...args: unknown[]): void {
  // Ошибки выводим всегда
  console.error(`[${category}]`, ...args);
}

/**
 * Debug info - выводит только в debug режиме
 * @param category - категория/модуль
 * @param args - аргументы для логирования
 */
export function debugInfo(category: string, ...args: unknown[]): void {
  if (isDebugEnabled()) {
    console.info(`[${category}]`, ...args);
  }
}

/**
 * Включить debug режим программно (для браузера)
 */
export function enableDebug(): void {
  if (typeof window !== 'undefined') {
    localStorage.setItem('DEBUG', 'true');
  }
}

/**
 * Выключить debug режим программно (для браузера)
 */
export function disableDebug(): void {
  if (typeof window !== 'undefined') {
    localStorage.removeItem('DEBUG');
  }
}

/**
 * detectTestCategoryAndType
 *
 * Heuristic determination of TestCategory + TestType from available metadata.
 * Used to pre-populate the save dialog; the user can always override the result.
 *
 * Inputs (all optional):
 *   fluidType      — already-determined FluidType (used to pick the category)
 *   filename       — original data file name; parsed for test-type keywords
 *   instrumentType — from parser metadata
 *   maxTemp        — maximum temperature recorded (°C)
 *   durationMin    — total duration (minutes)
 *   reagentCategories — resolved catalog categories of the reagent recipe
 */

import type { FluidType } from '@/lib/constants/fluid-types';
import type { TestCategory, TestType } from '@/lib/constants/test-types';

export interface TestTypeDetectionInput {
    fluidType?: FluidType;
    filename?: string;
    instrumentType?: string;
    maxTemp?: number;
    durationMin?: number;
    reagentCategories?: string[];
}

export interface TestTypeDetectionResult {
    testCategory: TestCategory;
    testType: TestType;
}

// ── Helpers ──────────────────────────────────────────────────────────────────

function matches(text: string, ...patterns: string[]): boolean {
    const lower = text.toLowerCase();
    return patterns.some(p => lower.includes(p.toLowerCase()));
}

// ── Category from FluidType ───────────────────────────────────────────────────

function categoryFromFluidType(ft?: FluidType): TestCategory {
    if (!ft) return 'Fracturing';
    if (ft === 'WBM' || ft === 'OBM' || ft === 'SBM') return 'Drilling';
    return 'Fracturing';
}

// ── Fracturing test-type heuristics ──────────────────────────────────────────

function detectFracturingType(
    filename: string,
    instrumentType: string,
    maxTemp: number,
    durationMin: number,
    cats: string[],
): TestType {
    const fn = filename;

    // Hydration — slow build-up protocol, filename keyword
    if (matches(fn, 'hydrat', 'гидрат', 'build-up', 'buildup', 'buildupviscosity')) {
        return 'Hydration';
    }

    // Crosslink time / window
    if (matches(fn, 'crosslink', 'xlink', 'сшив', 'сшитый', 'cross-link') ||
        cats.some(c => c.includes('crosslinker'))) {
        // Only classify as CrosslinkTest if the filename explicitly says so
        if (matches(fn, 'crosslink', 'xlink', 'сшив') || matches(fn, 'crosslink-time', 'xlink-time')) {
            return 'CrosslinkTest';
        }
        // Otherwise it's likely shear viscosity with crosslinker
    }

    // Shear degradation — high+low shear protocol
    if (matches(fn, 'degrad', 'destr', 'degradation', 'деград', 'деструкц')) {
        return 'ShearDegradation';
    }

    // Thermal stability — temperature ramp, hot test
    if (maxTemp >= 80 || matches(fn, 'thermal', 'temperature', 'heat', 'hot', 'темп', 'нагрев', 'hpht')) {
        return 'ThermalStability';
    }

    // Break test
    if (matches(fn, 'break', 'брейк', 'деструкт', 'destroy', 'destruct') ||
        cats.some(c => c.includes('breaker'))) {
        if (matches(fn, 'break', 'брейк', 'деструкт')) return 'BreakTest';
    }

    // Residue / filterability
    if (matches(fn, 'residue', 'остат', 'filter', 'фильтр')) {
        return 'FilterResidueTest';
    }

    // Proppant transport
    if (matches(fn, 'proppant', 'проппант', 'transport', 'settling', 'sett', 'седим')) {
        return 'ProppantTransport';
    }

    // Friction reduction (slickwater typical)
    if (matches(fn, 'friction', 'fr-test', 'drag', 'снижение трения', 'понижение трения') ||
        cats.some(c => c.includes('friction reducer'))) {
        return 'FrictionReduction';
    }

    // Compatibility with reservoir fluids
    if (matches(fn, 'compat', 'совмест', 'emulsion', 'эмульс')) {
        return 'FluidsCompatibility';
    }

    // Biostability
    if (matches(fn, 'biocide', 'биоцид', 'biostab', 'биостаб', 'bacteria', 'бактер')) {
        return 'Biostability';
    }

    // Long test without special keywords → could be shear viscosity flow curve
    // Short test (<30 min) with no high temp → shear viscosity default
    return 'ShearViscosity';
}

// ── Drilling test-type heuristics ─────────────────────────────────────────────

function detectDrillingType(
    filename: string,
    maxTemp: number,
    durationMin: number,
    cats: string[],
): TestType {
    const fn = filename;

    if (matches(fn, 'filtration', 'фильтр', 'filtrate', 'api', 'hpht')) return 'Filtration';
    if (matches(fn, 'sag', 'settling', 'sedim', 'седим', 'барит')) return 'BariteSag';
    if (matches(fn, 'thixo', 'gel', 'гель', 'тиксо', 'recovery')) return 'Thixotropy';
    if (matches(fn, 'aging', 'hot roll', 'hotroll', 'термостар', 'старен')) return 'ThermalAging';
    if (matches(fn, 'shale', 'inhibit', 'ингиб', 'сланц')) return 'ShaleInhibition';
    if (matches(fn, 'lcm', 'bridg', 'ppa', 'поглощен')) return 'LCMBridging';
    if (matches(fn, 'contamination', 'загрязн', 'цемент', 'ангидрит')) return 'ContaminationTest';
    if (matches(fn, 'es', 'electrical', 'stability', 'электростаб')) return 'ElectricalStability';
    if (matches(fn, 'emulsion', 'эмульс', 'obm emul')) return 'EmulsionStability';
    if (matches(fn, 'lubric', 'смазк', 'cof', 'coeff friction')) return 'Lubricity';
    if (matches(fn, 'retort', 'oil/water', 'o/w/s', 'ретор')) return 'Retort';
    if (matches(fn, 'sand', 'песок', 'solids')) return 'SandContent';
    if (matches(fn, 'pH', 'alkalin', 'щелочн', 'известь')) return 'PhAlkalinity';
    if (matches(fn, 'chloride', 'хлорид', 'hardness', 'жёсткость')) return 'ChlorideHardness';
    if (matches(fn, 'mbt', 'methylene', 'clay activity', 'мбт', 'мет.синий')) return 'MBT';
    if (matches(fn, 'density', 'weight', 'плотность', 'mud weight')) return 'MudWeight';

    return 'MudRheology';
}

// ── Public API ────────────────────────────────────────────────────────────────

export function detectTestCategoryAndType(
    input: TestTypeDetectionInput,
): TestTypeDetectionResult {
    const {
        fluidType,
        filename = '',
        instrumentType = '',
        maxTemp = 0,
        durationMin = 0,
        reagentCategories = [],
    } = input;

    const cats = reagentCategories.map(c => c.toLowerCase());

    // Water analysis — filename keyword takes highest priority
    if (matches(filename, 'water', 'вода', 'ионн', 'mineral', 'water-quality', 'water quality', 'совместим')) {
        return { testCategory: 'General', testType: 'WaterAnalysis' };
    }

    const testCategory = categoryFromFluidType(fluidType);

    if (testCategory === 'Drilling') {
        return {
            testCategory,
            testType: detectDrillingType(filename, maxTemp, durationMin, cats),
        };
    }

    // Fracturing (default branch)
    return {
        testCategory,
        testType: detectFracturingType(filename, instrumentType, maxTemp, durationMin, cats),
    };
}

